def _direct_prime_certificate_target_ids(spec: Mapping[str, Any]) -> list[str]:
    prefix = str(spec["case_prefix"])
    support_targets = (
        [str(spec["support_target"])] if "support_target" in spec else []
    )
    row_targets = [
        target_id
        for row in spec["rows"]
        for target_id in (
            f"{prefix}_p{row['p']}_prime_witness",
            f"{prefix}_p{row['p']}_CanonicalWitnessRowCase",
        )
    ]
    return [
        *support_targets,
        *row_targets,
        str(spec["certificate"]),
        str(spec["period_target"]),
    ]


def _direct_prime_certificate_expected_theorems(
    spec: Mapping[str, Any],
) -> list[str]:
    certificate_definition = str(spec["certificate"])
    return [
        target_id
        for target_id in _direct_prime_certificate_target_ids(spec)
        if target_id != certificate_definition
    ]


def _direct_prime_certificate_survivor_cache_key(
    spec: Mapping[str, Any],
) -> str:
    rows = []
    for row in spec["rows"]:
        row_payload = {
            "p": int(row["p"]),
            "q": int(row["q"]),
            "component_quotient": int(row["component_quotient"]),
        }
        if "cofactor" in row:
            row_payload["cofactor"] = int(row["cofactor"])
        if "reduced_cofactor" in row:
            row_payload["reduced_cofactor"] = int(row["reduced_cofactor"])
        if "q_factorization_exponent" in row:
            row_payload["q_factorization_exponent"] = int(
                row["q_factorization_exponent"]
            )
        if "A_q_factorization_exponent" in row:
            row_payload["A_q_factorization_exponent"] = int(
                row["A_q_factorization_exponent"]
            )
        rows.append(row_payload)
    payload = {
        "family_id": FINITE_CERTIFICATE_FACTORY_FAMILY_ID,
        "b": int(spec["b"]),
        "L": int(spec["L"]),
        "A": int(spec["A"]),
        "B": int(spec["B"]),
        "Q": int(spec["Q"]),
        "support": [int(p) for p in spec["support"]],
        "rows": rows,
    }
    digest = hashlib.sha256(
        json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")
    ).hexdigest()
    return f"{FINITE_CERTIFICATE_FACTORY_FAMILY_ID}:sha256:{digest}"


def _direct_prime_generated_target_registry(
    specs: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    entries = []
    all_target_ids: list[str] = []
    survivor_cache_keys: list[str] = []
    for spec in specs:
        target_ids = _direct_prime_certificate_target_ids(spec)
        survivor_cache_key = _direct_prime_certificate_survivor_cache_key(spec)
        all_target_ids.extend(target_ids)
        survivor_cache_keys.append(survivor_cache_key)
        entries.append(
            {
                "spec_id": str(spec["spec_id"]),
                "survivor_cache_key": survivor_cache_key,
                "generated_module_path": _direct_prime_certificate_lean_module_path_string(
                    spec
                ),
                "target_count": len(target_ids),
                "target_ids": target_ids,
                "expected_theorems": _direct_prime_certificate_expected_theorems(
                    spec
                ),
                "period_target": str(spec["period_target"]),
                "certificate": str(spec["certificate"]),
                "support_target": str(spec.get("support_target", "")),
            }
        )
    lift_registry = _direct_prime_denominator_invisible_lift_registry()
    lift_target_ids = [
        target_id
        for binding in lift_registry["bindings"]
        for target_id in binding["target_ids"]
    ]
    all_target_ids.extend(lift_target_ids)
    duplicate_target_ids = sorted(
        target_id
        for target_id, count in Counter(all_target_ids).items()
        if count > 1
    )
    duplicate_survivor_cache_keys = sorted(
        survivor_cache_key
        for survivor_cache_key, count in Counter(survivor_cache_keys).items()
        if count > 1
    )
    return {
        "schema_version": DIRECT_PRIME_GENERATED_TARGET_REGISTRY_SCHEMA_VERSION,
        "status": (
            "PASS"
            if not duplicate_target_ids
            and not duplicate_survivor_cache_keys
            and lift_registry["status"] == "PASS"
            else "FAIL"
        ),
        "entry_count": len(entries),
        "certificate_entry_count": len(entries),
        "lift_entry_count": lift_registry["binding_count"],
        "target_count": len(all_target_ids),
        "certificate_target_count": len(all_target_ids) - len(lift_target_ids),
        "lift_target_count": len(lift_target_ids),
        "duplicate_target_id_count": len(duplicate_target_ids),
        "duplicate_target_ids": duplicate_target_ids,
        "duplicate_survivor_cache_key_count": len(duplicate_survivor_cache_keys),
        "duplicate_survivor_cache_keys": duplicate_survivor_cache_keys,
        "generated_module_policy": DIRECT_PRIME_GENERATED_MODULE_POLICY,
        "generated_module_path": DIRECT_PRIME_GENERATED_LEAN_MODULE.as_posix(),
        "entries": entries,
        "lift_entries": lift_registry["bindings"],
    }


def _direct_prime_b12_l12_denominator_lattice_spec_ids(
    specs: Sequence[Mapping[str, Any]],
) -> tuple[str, ...]:
    spec_ids: list[str] = []
    for spec in specs:
        role = str(spec.get("role", ""))
        if int(spec.get("b", 0)) != 12 or int(spec.get("L", 0)) != 12:
            continue
        if (
            role == "non_squarefree_composite_base_scale_denominator_skip"
            or "denominator_lattice" in role
        ):
            spec_ids.append(str(spec["spec_id"]))
    return tuple(spec_ids)


def _is_prime_small(n: int) -> bool:
    if n < 2:
        return False
    return all(n % candidate != 0 for candidate in range(2, int(n**0.5) + 1))


class DirectPrimeFactorizationBlocked(RuntimeError):
    """Raised when direct-prime autofill would otherwise do unsafe factoring."""


def _factorization_backend_for_n(n: int) -> str:
    if n <= 1:
        return "trivial"
    if _sympy_factorint is not None:
        return "sympy"
    if n <= DIRECT_PRIME_TRIAL_DIVISION_N_LIMIT:
        return "trial_division_bounded"
    return "blocked_large_without_sympy"


def _direct_prime_factorization_backend_receipt() -> dict[str, Any]:
    return {
        "backend": "sympy" if _sympy_factorint is not None else "trial_division_bounded",
        "sympy_available": _sympy_factorint is not None,
        "cache_enabled": True,
        "trial_division_n_limit": DIRECT_PRIME_TRIAL_DIVISION_N_LIMIT,
        "large_without_sympy_policy": "fail_fast",
    }


@lru_cache(maxsize=None)
def _factorint_small_cached(n: int) -> tuple[tuple[int, int], ...]:
    if n <= 1:
        return ()
    if _sympy_factorint is not None:
        return tuple(
            sorted(
                (int(prime), int(exponent))
                for prime, exponent in _sympy_factorint(n).items()
            )
        )
    if n > DIRECT_PRIME_TRIAL_DIVISION_N_LIMIT:
        raise DirectPrimeFactorizationBlocked(
            "direct-prime certificate autofill requires sympy.factorint for "
            f"n={n}; bounded trial division limit is "
            f"{DIRECT_PRIME_TRIAL_DIVISION_N_LIMIT}"
        )
    factors: dict[int, int] = {}
    candidate = 2
    remainder = n
    while candidate * candidate <= remainder:
        while remainder % candidate == 0:
            factors[candidate] = factors.get(candidate, 0) + 1
            remainder //= candidate
        candidate += 1 if candidate == 2 else 2
    if remainder > 1:
        factors[remainder] = factors.get(remainder, 0) + 1
    return tuple(sorted(factors.items()))


def _factorint_small(n: int) -> dict[int, int]:
    return dict(_factorint_small_cached(n))


def _prime_factor_support(n: int) -> list[int]:
    return sorted(_factorint_small(n))


def _factorization_exponent(n: int, q: int) -> int:
    if q <= 1:
        return 0
    exponent = 0
    while n > 0 and n % q == 0:
        exponent += 1
        n //= q
    return exponent


def _direct_prime_certificate_expected_B(b: int, L: int) -> int:
    return b**L - 1


def _direct_prime_certificate_expected_Q(b: int, L: int, A: int) -> int:
    B = _direct_prime_certificate_expected_B(b, L)
    return B // math.gcd(A, B)


def _direct_prime_certificate_component_quotient(
    b: int,
    L: int,
    p: int,
) -> int | None:
    if p <= 0 or L % p != 0:
        return None
    divisor = b ** (L // p) - 1
    if divisor == 0:
        return None
    B = _direct_prime_certificate_expected_B(b, L)
    if B % divisor != 0:
        return None
    return B // divisor


def _direct_prime_certificate_select_witness_q(
    component_quotient: int,
    A: int,
) -> int | None:
    for q, quotient_q_exp in sorted(_factorint_small(component_quotient).items()):
        if quotient_q_exp > _factorization_exponent(A, q):
            return q
    return None


def _direct_prime_certificate_expected_names(spec: Mapping[str, Any]) -> dict[str, str]:
    b = int(spec["b"])
    L = int(spec["L"])
    A = int(spec["A"])
    Q = int(spec.get("Q", _direct_prime_certificate_expected_Q(b, L, A)))
    return {
        "case_prefix": f"concrete_generated_b{b}_F{L}_A{A}",
        "support_target": f"concrete_generated_b{b}_F{L}_factorization_support_cases",
        "certificate": f"emittedCertificate_b{b}_L{L}_A{A}",
        "period_target": f"orderOf_b{b}_mod{Q}_eq_{L}_from_emittedCertificate_denNorm",
    }


def _direct_prime_certificate_case_support_target(
    spec: Mapping[str, Any],
) -> str:
    return f"{spec['case_prefix']}_factorization_support_cases"


def _direct_prime_certificate_support_target_style(
    spec: Mapping[str, Any],
) -> str:
    support_target = spec.get("support_target")
    if not support_target:
        return "kernel_shared_or_not_emitted"
    support_target = str(support_target)
    expected_names = _direct_prime_certificate_expected_names(spec)
    if support_target == expected_names["support_target"]:
        return "base_l_shared"
    if support_target == _direct_prime_certificate_case_support_target(spec):
        return "case_scoped"
    return "custom"


def _direct_prime_certificate_default_lean_module_path(spec_id: str) -> Path:
    shard_path = DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_MODULES.get(spec_id)
    if shard_path is not None:
        return shard_path
    if DIRECT_PRIME_GENERATED_MODULE_POLICY == "all_direct_prime_specs":
        return DIRECT_PRIME_GENERATED_LEAN_MODULE
    return DIRECT_PRIME_KERNEL_LEAN_MODULE


def _lean_import_from_module_path(path: Path) -> str:
    rel = path.relative_to(LEAN_MICROKERNEL_ROOT).with_suffix("")
    return ".".join(rel.parts)


def _direct_prime_certificate_lean_module_path(spec: Mapping[str, Any]) -> Path:
    return Path(
        spec.get(
            "lean_module_path",
            _direct_prime_certificate_default_lean_module_path(str(spec["spec_id"])),
        )
    )


def _direct_prime_certificate_lean_module_path_string(spec: Mapping[str, Any]) -> str:
    return _direct_prime_certificate_lean_module_path(spec).as_posix()


def _direct_prime_certificate_spec_needs_autofill(spec: Mapping[str, Any]) -> bool:
    required_fields = ("case_prefix", "certificate", "period_target", "B", "Q", "support")
    if any(field not in spec for field in required_fields):
        return True
    if "rows" not in spec:
        return True
    return any(
        "q" not in row
        or "component_quotient" not in row
        or ("cofactor" not in row and "reduced_cofactor" not in row)
        for row in spec["rows"]
    )


def _normalize_direct_prime_certificate_spec(
    spec: Mapping[str, Any],
) -> dict[str, Any]:
    normalized = dict(spec)
    b = int(normalized["b"])
    L = int(normalized["L"])
    A = int(normalized["A"])
    B = _direct_prime_certificate_expected_B(b, L)
    Q = _direct_prime_certificate_expected_Q(b, L, A)
    needs_autofill = _direct_prime_certificate_spec_needs_autofill(spec)

    normalized.setdefault("B", B)
    normalized.setdefault("Q", Q)
    normalized.setdefault("support", _prime_factor_support(L))
    expected_names = _direct_prime_certificate_expected_names(normalized)
    normalized.setdefault("case_prefix", expected_names["case_prefix"])
    normalized.setdefault("certificate", expected_names["certificate"])
    normalized.setdefault("period_target", expected_names["period_target"])
    normalized.setdefault(
        "lean_module_path",
        _direct_prime_certificate_default_lean_module_path(
            str(normalized["spec_id"])
        ).as_posix(),
    )
    if str(normalized["spec_id"]) in DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_SPEC_IDS:
        normalized.setdefault(
            "support_target",
            _direct_prime_certificate_case_support_target(normalized),
        )
    if needs_autofill:
        normalized.setdefault("support_target", expected_names["support_target"])

    rows: list[dict[str, Any]] = []
    input_rows = spec.get(
        "rows",
        [{"p": p} for p in normalized["support"]],
    )
    for row in input_rows:
        normalized_row = dict(row)
        p = int(normalized_row["p"])
        component_quotient = _direct_prime_certificate_component_quotient(b, L, p)
        if component_quotient is not None:
            normalized_row.setdefault("component_quotient", component_quotient)
        component_quotient = int(normalized_row.get("component_quotient", 0))
        q_was_autofilled = "q" not in normalized_row
        if q_was_autofilled:
            selected_q = _direct_prime_certificate_select_witness_q(
                component_quotient,
                A,
            )
            if selected_q is not None:
                normalized_row["q"] = selected_q
                normalized_row.setdefault(
                    "q_source",
                    "selected_by_factorization_surplus",
                )
        q = int(normalized_row.get("q", 0))
        quotient_q_exp = _factorization_exponent(component_quotient, q) if q else 0
        A_q_exp = _factorization_exponent(A, q) if q else 0
        q_power = q**quotient_q_exp if q else 0
        if q > 0 and q_power > 0 and component_quotient % q_power == 0:
            reduced_cofactor = component_quotient // q_power
            if q_was_autofilled and quotient_q_exp > 1:
                normalized_row.setdefault(
                    "q_factorization_exponent",
                    quotient_q_exp,
                )
                normalized_row.setdefault("A_q_factorization_exponent", A_q_exp)
                normalized_row.setdefault("reduced_cofactor", reduced_cofactor)
            elif component_quotient % q == 0:
                normalized_row.setdefault("cofactor", component_quotient // q)
        if (
            q_was_autofilled
            and (
                len(str(component_quotient)) >= DIRECT_PRIME_LARGE_ROW_DIGITS
                or q >= DIRECT_PRIME_LARGE_WITNESS_Q
            )
        ):
            if q >= DIRECT_PRIME_HUGE_WITNESS_Q:
                normalized_row.setdefault(
                    "prime_witness_proof_strategy",
                    DIRECT_PRIME_HUGE_WITNESS_PROOF_STRATEGY,
                )
            else:
                normalized_row.setdefault(
                    "set_option_max_rec_depth",
                    DIRECT_PRIME_LARGE_ROW_MAX_REC_DEPTH,
                )
        rows.append(normalized_row)
    normalized["rows"] = rows
    return normalized


def _dedupe_direct_prime_certificate_support_targets(
    specs: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    specs_by_base_support: dict[tuple[str, str], list[Mapping[str, Any]]] = {}
    for spec in specs:
        if not spec.get("support_target"):
            continue
        expected_names = _direct_prime_certificate_expected_names(spec)
        key = (
            _direct_prime_certificate_lean_module_path_string(spec),
            expected_names["support_target"],
        )
        specs_by_base_support.setdefault(key, []).append(spec)

    duplicate_base_support_targets = {
        key
        for key, grouped_specs in specs_by_base_support.items()
        if len(grouped_specs) > 1
    }
    deduped: list[dict[str, Any]] = []
    for spec in specs:
        normalized = dict(spec)
        expected_names = _direct_prime_certificate_expected_names(normalized)
        key = (
            _direct_prime_certificate_lean_module_path_string(normalized),
            expected_names["support_target"],
        )
        if (
            key in duplicate_base_support_targets
            and normalized.get("support_target") == expected_names["support_target"]
        ):
            normalized["support_target"] = (
                _direct_prime_certificate_case_support_target(normalized)
            )
            normalized["support_target_naming_policy"] = (
                "case_scoped_for_duplicate_generated_support"
            )
        else:
            normalized["support_target_naming_policy"] = (
                _direct_prime_certificate_support_target_style(normalized)
            )
        deduped.append(normalized)
    return deduped


def _direct_prime_certificate_explicit_field_drift_check(
    raw_spec: Mapping[str, Any],
    normalized_spec: Mapping[str, Any],
) -> dict[str, Any]:
    mismatches: list[dict[str, Any]] = []
    rows_synthesized_from_support = "rows" not in raw_spec
    if rows_synthesized_from_support:
        support = list(normalized_spec["support"])
        row_ps = [row["p"] for row in normalized_spec["rows"]]
        if row_ps != support:
            mismatches.append(
                {
                    "field": "rows[].p",
                    "actual": row_ps,
                    "expected": support,
                }
            )
    for key, raw_value in raw_spec.items():
        if key == "rows":
            for index, raw_row in enumerate(raw_value):
                normalized_row = normalized_spec["rows"][index]
                for row_key, row_value in raw_row.items():
                    if normalized_row.get(row_key) != row_value:
                        mismatches.append(
                            {
                                "field": f"rows[{index}].{row_key}",
                                "actual": normalized_row.get(row_key),
                                "expected": row_value,
                            }
                        )
            continue
        if normalized_spec.get(key) != raw_value:
            mismatches.append(
                {
                    "field": key,
                    "actual": normalized_spec.get(key),
                    "expected": raw_value,
                }
            )
    return {
        "spec_id": raw_spec["spec_id"],
        "status": "PASS" if not mismatches else "FAIL",
        "mismatch_count": len(mismatches),
        "mismatches": mismatches,
        "rows_synthesized_from_support": rows_synthesized_from_support,
        "row_source": (
            "synthesized_from_support"
            if rows_synthesized_from_support
            else "provided_or_partially_autofilled"
        ),
    }


def _direct_prime_raw_row_has_max_rec_depth_override(
    spec_id: str,
    p: int,
) -> bool:
    for raw_spec in EMITTED_CERTIFICATE_DIRECT_PRIME_SPEC_INPUTS:
        if str(raw_spec["spec_id"]) != spec_id:
            continue
        for raw_row in raw_spec.get("rows", []):
            if int(raw_row["p"]) == p:
                return "set_option_max_rec_depth" in raw_row
        return False
    return False


def _direct_prime_helper_compact_fact_receipt(
    spec: Mapping[str, Any],
    row: Mapping[str, Any],
) -> dict[str, Any]:
    b = int(spec["b"])
    L = int(spec["L"])
    A = int(spec["A"])
    p = int(row["p"])
    q = int(row.get("q", 0))
    quotient = int(row.get("component_quotient", 0))
    expected_quotient = _direct_prime_certificate_component_quotient(b, L, p)
    expected_q_exp = _factorization_exponent(quotient, q) if q else 0
    expected_A_exp = _factorization_exponent(A, q) if q else 0
    declared_q_exp = int(row.get("q_factorization_exponent", expected_q_exp))
    declared_A_exp = int(row.get("A_q_factorization_exponent", expected_A_exp))
    q_power = q**declared_q_exp if q > 0 else 0
    expected_q_power = q**expected_q_exp if q > 0 else 0
    if "reduced_cofactor" in row:
        reduced_cofactor = int(row["reduced_cofactor"])
        reduced_cofactor_source = "row.reduced_cofactor"
    elif q_power and quotient % q_power == 0:
        reduced_cofactor = quotient // q_power
        reduced_cofactor_source = "derived_from_declared_exponent"
    else:
        reduced_cofactor = int(row.get("cofactor", 0))
        reduced_cofactor_source = "row.cofactor_fallback"
    expected_reduced_cofactor = (
        quotient // expected_q_power
        if expected_q_power and quotient % expected_q_power == 0
        else None
    )
    hfactor_rhs = q_power * reduced_cofactor if q_power else None
    checks = [
        {
            "check_id": "helper_q_is_prime",
            "ok": _is_prime_small(q),
            "q": q,
        },
        {
            "check_id": "helper_quotient_matches_formula",
            "ok": quotient == expected_quotient,
            "actual": quotient,
            "expected": expected_quotient,
        },
        {
            "check_id": "helper_quotient_nonzero",
            "ok": quotient != 0,
            "quotient": quotient,
        },
        {
            "check_id": "helper_q_factorization_exponent_matches_quotient",
            "ok": declared_q_exp == expected_q_exp,
            "actual": declared_q_exp,
            "expected": expected_q_exp,
        },
        {
            "check_id": "helper_AExponent_matches_A",
            "ok": declared_A_exp == expected_A_exp,
            "actual": declared_A_exp,
            "expected": expected_A_exp,
        },
        {
            "check_id": "helper_reducedCofactor_matches",
            "ok": reduced_cofactor == expected_reduced_cofactor,
            "actual": reduced_cofactor,
            "expected": expected_reduced_cofactor,
        },
        {
            "check_id": "helper_hfactor_matches",
            "ok": hfactor_rhs == quotient,
            "actual": hfactor_rhs,
            "expected": quotient,
        },
        {
            "check_id": "helper_AExponent_lt_exponent",
            "ok": declared_A_exp < declared_q_exp,
            "AExponent": declared_A_exp,
            "exponent": declared_q_exp,
        },
    ]
    failed_check_ids = [
        str(check["check_id"]) for check in checks if not bool(check["ok"])
    ]
    return {
        "status": "PASS" if not failed_check_ids else "FAIL",
        "helper_theorem": "primeComponentWitness_of_prime_power_cofactor",
        "compact_facts": {
            "q": q,
            "quotient": quotient,
            "exponent": declared_q_exp,
            "AExponent": declared_A_exp,
            "reducedCofactor": reduced_cofactor,
            "hfactor_rhs": hfactor_rhs,
        },
        "expected_facts": {
            "quotient": expected_quotient,
            "exponent": expected_q_exp,
            "AExponent": expected_A_exp,
            "reducedCofactor": expected_reduced_cofactor,
        },
        "reducedCofactor_source": reduced_cofactor_source,
        "checks": checks,
        "failed_check_ids": failed_check_ids,
    }


def _direct_prime_row_max_rec_depth_policy(
    spec: Mapping[str, Any],
    row: Mapping[str, Any],
) -> dict[str, Any]:
    p = int(row["p"])
    q = int(row.get("q", 0))
    component_quotient = int(row.get("component_quotient", 0))
    component_quotient_digits = len(str(abs(component_quotient)))
    trigger_reasons: list[str] = []
    if component_quotient_digits >= DIRECT_PRIME_LARGE_ROW_DIGITS:
        trigger_reasons.append("large_component_quotient_digits")
    if q >= DIRECT_PRIME_LARGE_WITNESS_Q:
        trigger_reasons.append("large_witness_q")
    if q >= DIRECT_PRIME_HUGE_WITNESS_Q:
        trigger_reasons.append("huge_witness_q")
    required_by_policy = (
        bool(trigger_reasons)
        and row.get("q_source") == "selected_by_factorization_surplus"
    )
    helper_required_by_policy = (
        required_by_policy and q >= DIRECT_PRIME_HUGE_WITNESS_Q
    )
    expected_proof_strategy = (
        DIRECT_PRIME_HUGE_WITNESS_PROOF_STRATEGY
        if helper_required_by_policy
        else "inline_factorization"
    )
    proof_strategy = row.get("prime_witness_proof_strategy", "inline_factorization")
    helper_backed = proof_strategy == DIRECT_PRIME_HUGE_WITNESS_PROOF_STRATEGY
    helper_fact_receipt = _direct_prime_helper_compact_fact_receipt(spec, row)
    helper_fact_failures = (
        list(helper_fact_receipt["failed_check_ids"]) if helper_backed else []
    )
    emitted_value = row.get("set_option_max_rec_depth")
    emitted = emitted_value is not None
    manual_override = _direct_prime_raw_row_has_max_rec_depth_override(
        str(spec["spec_id"]),
        p,
    )
    expected_value = None
    max_rec_depth_required = required_by_policy and not helper_required_by_policy
    if max_rec_depth_required:
        expected_value = DIRECT_PRIME_LARGE_ROW_MAX_REC_DEPTH
    missing_required_guard = max_rec_depth_required and not emitted
    wrong_guard_value = (
        max_rec_depth_required
        and emitted
        and int(emitted_value) != expected_value
    )
    missing_required_helper = helper_required_by_policy and not helper_backed
    wrong_helper_strategy = helper_backed and proof_strategy != expected_proof_strategy
    helper_max_rec_depth_emitted = helper_backed and emitted
    status = (
        "PASS"
        if not missing_required_guard
        and not wrong_guard_value
        and not missing_required_helper
        and not wrong_helper_strategy
        and not helper_fact_failures
        and not helper_max_rec_depth_emitted
        else "FAIL"
    )
    helper_receipt_required = helper_required_by_policy or helper_backed
    return {
        "spec_id": spec["spec_id"],
        "p": p,
        "q": q,
        "component_quotient": component_quotient,
        "component_quotient_digit_count": component_quotient_digits,
        "set_option_max_rec_depth_emitted": emitted,
        "set_option_max_rec_depth": emitted_value,
        "expected_set_option_max_rec_depth": expected_value,
        "required_by_policy": required_by_policy,
        "max_rec_depth_required_by_policy": max_rec_depth_required,
        "helper_required_by_policy": helper_required_by_policy,
        "prime_witness_proof_strategy": proof_strategy,
        "expected_prime_witness_proof_strategy": expected_proof_strategy,
        "helper_backed": helper_backed,
        "missing_required_helper": missing_required_helper,
        "helper_fact_status": (
            helper_fact_receipt["status"]
            if helper_receipt_required
            else "not_helper_route"
        ),
        "helper_fact_failures": helper_fact_failures,
        "helper_compact_facts": (
            helper_fact_receipt["compact_facts"]
            if helper_receipt_required
            else None
        ),
        "helper_expected_facts": (
            helper_fact_receipt["expected_facts"]
            if helper_receipt_required
            else None
        ),
        "helper_fact_checks": (
            helper_fact_receipt["checks"] if helper_receipt_required else []
        ),
        "helper_no_max_rec_depth_needed": helper_backed,
        "helper_max_rec_depth_emitted": helper_max_rec_depth_emitted,
        "trigger_reasons": trigger_reasons,
        "trigger_reason": trigger_reasons[0] if trigger_reasons else None,
        "manual_override": manual_override,
        "q_source": row.get("q_source"),
        "large_witness_q_threshold": DIRECT_PRIME_LARGE_WITNESS_Q,
        "huge_witness_q_threshold": DIRECT_PRIME_HUGE_WITNESS_Q,
        "huge_witness_proof_strategy": DIRECT_PRIME_HUGE_WITNESS_PROOF_STRATEGY,
        "large_component_quotient_digit_threshold": DIRECT_PRIME_LARGE_ROW_DIGITS,
        "status": status,
    }


def _direct_prime_certificate_proof_policy_check(
    spec: Mapping[str, Any],
) -> dict[str, Any]:
    row_policies = [
        _direct_prime_row_max_rec_depth_policy(spec, row)
        for row in spec["rows"]
    ]
    relevant_rows = [
        row
        for row in row_policies
        if row["required_by_policy"]
        or row["set_option_max_rec_depth_emitted"]
        or row["helper_backed"]
    ]
    status = (
        "PASS"
        if all(row["status"] == "PASS" for row in row_policies)
        else "FAIL"
    )
    policy = {
        "spec_id": spec["spec_id"],
        "status": status,
        "row_count": len(relevant_rows),
        "required_guard_count": sum(
            1 for row in row_policies if row["required_by_policy"]
        ),
        "emitted_guard_count": sum(
            1 for row in row_policies if row["set_option_max_rec_depth_emitted"]
        ),
        "manual_override_count": sum(
            1 for row in row_policies if row["manual_override"]
        ),
        "helper_backed_row_count": sum(
            1 for row in row_policies if row["helper_backed"]
        ),
        "required_helper_count": sum(
            1 for row in row_policies if row["helper_required_by_policy"]
        ),
        "helper_fact_failure_count": sum(
            len(row["helper_fact_failures"]) for row in row_policies
        ),
        "helper_max_rec_depth_emitted_count": sum(
            1 for row in row_policies if row["helper_max_rec_depth_emitted"]
        ),
        "large_witness_q_threshold": DIRECT_PRIME_LARGE_WITNESS_Q,
        "huge_witness_q_threshold": DIRECT_PRIME_HUGE_WITNESS_Q,
        "huge_witness_proof_strategy": DIRECT_PRIME_HUGE_WITNESS_PROOF_STRATEGY,
        "large_component_quotient_digit_threshold": DIRECT_PRIME_LARGE_ROW_DIGITS,
        "max_rec_depth_value": DIRECT_PRIME_LARGE_ROW_MAX_REC_DEPTH,
        "huge_witness_max_rec_depth_value": DIRECT_PRIME_HUGE_WITNESS_MAX_REC_DEPTH,
        "rows": relevant_rows,
    }
    issues: list[str] = []
    for row in relevant_rows:
        prefix = f"row_p{row['p']}"
        if (
            row["max_rec_depth_required_by_policy"]
            and not row["set_option_max_rec_depth_emitted"]
        ):
            issues.append(f"{prefix}:missing_required_max_rec_depth_guard")
        if (
            row["max_rec_depth_required_by_policy"]
            and row["set_option_max_rec_depth_emitted"]
            and row["set_option_max_rec_depth"]
            != row["expected_set_option_max_rec_depth"]
        ):
            issues.append(f"{prefix}:wrong_max_rec_depth_guard")
        if row["missing_required_helper"]:
            issues.append(f"{prefix}:missing_required_helper_strategy")
        if row["helper_max_rec_depth_emitted"]:
            issues.append(f"{prefix}:forbidden_helper_max_rec_depth_guard")
        for failed_check_id in row["helper_fact_failures"]:
            issues.append(f"{prefix}:helper_fact:{failed_check_id}")
    policy["issue_count"] = len(issues)
    policy["issues"] = issues
    return policy


def _direct_prime_certificate_spec_validation(spec: Mapping[str, Any]) -> dict[str, Any]:
    b = int(spec["b"])
    L = int(spec["L"])
    A = int(spec["A"])
    B = int(spec["B"])
    Q = int(spec["Q"])
    support = [int(value) for value in spec["support"]]
    issues: list[str] = []
    checks: list[dict[str, Any]] = []

    def record(check_id: str, ok: bool, **details: Any) -> None:
        if not ok:
            issues.append(check_id)
        checks.append({"check_id": check_id, "ok": ok, **details})

    expected_B = b**L - 1
    record("B_equals_b_pow_L_minus_one", B == expected_B, actual=B, expected=expected_B)
    gcd_A_B = math.gcd(A, B)
    expected_Q = B // gcd_A_B if gcd_A_B else 0
    record(
        "Q_equals_B_div_gcd_A_B",
        Q == expected_Q and gcd_A_B > 0 and B % gcd_A_B == 0,
        actual=Q,
        expected=expected_Q,
        gcd_A_B=gcd_A_B,
    )
    expected_support = _prime_factor_support(L)
    record(
        "support_equals_factorization_support_L",
        support == expected_support,
        actual=support,
        expected=expected_support,
    )
    row_ps = [int(row["p"]) for row in spec.get("rows", [])]
    record(
        "rows_cover_support_exactly",
        sorted(row_ps) == expected_support and len(row_ps) == len(expected_support),
        actual=row_ps,
        expected=expected_support,
    )
    duplicate_row_ps = sorted(
        {p for p, count in Counter(row_ps).items() if count > 1}
    )
    record(
        "row_p_values_unique",
        not duplicate_row_ps,
        duplicate_p_values=duplicate_row_ps,
    )

    expected_names = _direct_prime_certificate_expected_names(spec)
    record(
        "case_prefix_matches_convention",
        str(spec["case_prefix"]) == expected_names["case_prefix"],
        actual=str(spec["case_prefix"]),
        expected=expected_names["case_prefix"],
    )
    if "support_target" in spec:
        allowed_support_targets = [
            expected_names["support_target"],
            _direct_prime_certificate_case_support_target(spec),
        ]
        record(
            "support_target_matches_convention",
            str(spec["support_target"]) in allowed_support_targets,
            actual=str(spec["support_target"]),
            expected=allowed_support_targets,
        )
    record(
        "certificate_matches_convention",
        str(spec["certificate"]) == expected_names["certificate"],
        actual=str(spec["certificate"]),
        expected=expected_names["certificate"],
    )
    record(
        "period_target_matches_convention",
        str(spec["period_target"]) == expected_names["period_target"],
        actual=str(spec["period_target"]),
        expected=expected_names["period_target"],
    )

    row_checks: list[dict[str, Any]] = []
    for row in spec["rows"]:
        p = int(row["p"])
        q = int(row["q"])
        component_quotient = int(row["component_quotient"])
        cofactor = int(row["cofactor"]) if "cofactor" in row else None
        expected_component_quotient = (
            expected_B // (b ** (L // p) - 1)
            if p > 0 and L % p == 0 and b ** (L // p) != 1
            else None
        )
        expected_cofactor = (
            component_quotient // q
            if q > 0 and component_quotient % q == 0
            else None
        )
        quotient_q_exp = _factorization_exponent(component_quotient, q)
        A_q_exp = _factorization_exponent(A, q)
        q_source = row.get("q_source")
        expected_selected_q = _direct_prime_certificate_select_witness_q(
            component_quotient,
            A,
        )
        expected_q_power = q**quotient_q_exp if q > 0 else None
        expected_reduced_cofactor = (
            component_quotient // expected_q_power
            if expected_q_power
            and expected_q_power > 0
            and component_quotient % expected_q_power == 0
            else None
        )
        row_ok = True

        def row_record(check_id: str, ok: bool, **details: Any) -> None:
            nonlocal row_ok
            row_ok = row_ok and ok
            if not ok:
                issues.append(f"row_p{p}:{check_id}")
            row_checks.append(
                {"p": p, "q": q, "check_id": check_id, "ok": ok, **details}
            )

        row_record("p_in_support", p in support, support=support)
        if q_source is not None:
            row_record(
                "q_source_allowed",
                str(q_source) in DIRECT_PRIME_ALLOWED_Q_SOURCES,
                actual=str(q_source),
                expected=list(DIRECT_PRIME_ALLOWED_Q_SOURCES),
            )
            if q_source == "selected_by_factorization_surplus":
                row_record(
                    "q_source_matches_selected_witness",
                    q == expected_selected_q,
                    actual=q,
                    expected=expected_selected_q,
                )
        row_record("q_is_prime", _is_prime_small(q))
        row_record(
            "q_divides_component_quotient",
            component_quotient % q == 0 if q > 0 else False,
            component_quotient=component_quotient,
        )
        row_record(
            "row_has_cofactor_or_reduced_cofactor",
            cofactor is not None or "reduced_cofactor" in row,
        )
        row_record(
            "component_quotient_matches_formula",
            component_quotient == expected_component_quotient,
            actual=component_quotient,
            expected=expected_component_quotient,
        )
        row_record(
            "cofactor_matches_component_quotient_div_q",
            cofactor == expected_cofactor if cofactor is not None else True,
            actual=cofactor,
            expected=expected_cofactor,
        )
        row_record(
            "q_times_cofactor_equals_component_quotient",
            q * cofactor == component_quotient if cofactor is not None else True,
            q=q,
            cofactor=cofactor,
            component_quotient=component_quotient,
        )
        row_record(
            "q_not_dvd_cofactor",
            cofactor % q != 0 if cofactor is not None and q > 0 else True,
            cofactor=cofactor,
        )
        if "q_factorization_exponent" in row:
            row_record(
                "q_factorization_exponent_matches_quotient",
                int(row["q_factorization_exponent"]) == quotient_q_exp,
                actual=int(row["q_factorization_exponent"]),
                expected=quotient_q_exp,
            )
        if "A_q_factorization_exponent" in row:
            row_record(
                "A_q_factorization_exponent_matches_A",
                int(row["A_q_factorization_exponent"]) == A_q_exp,
                actual=int(row["A_q_factorization_exponent"]),
                expected=A_q_exp,
            )
        if "reduced_cofactor" in row:
            reduced_cofactor = int(row["reduced_cofactor"])
            row_record(
                "reduced_cofactor_matches_component_quotient_div_q_power",
                reduced_cofactor == expected_reduced_cofactor,
                actual=reduced_cofactor,
                expected=expected_reduced_cofactor,
                q_factorization_exponent=quotient_q_exp,
            )
            row_record(
                "q_power_times_reduced_cofactor_equals_component_quotient",
                expected_q_power * reduced_cofactor == component_quotient
                if expected_q_power
                else False,
                q=q,
                q_factorization_exponent=quotient_q_exp,
                reduced_cofactor=reduced_cofactor,
                component_quotient=component_quotient,
            )
            row_record(
                "q_not_dvd_reduced_cofactor",
                reduced_cofactor % q != 0 if q > 0 else False,
                reduced_cofactor=reduced_cofactor,
            )
        row_record(
            "component_quotient_q_factorization_exceeds_A",
            quotient_q_exp > A_q_exp,
            component_quotient_q_factorization=quotient_q_exp,
            A_q_factorization=A_q_exp,
        )
        checks.append(
            {
                "check_id": f"row_p{p}_aggregate",
                "ok": row_ok,
                "p": p,
                "q": q,
            }
        )

    return {
        "status": "PASS" if not issues else "FAIL",
        "issue_count": len(issues),
        "issues": issues,
        "check_count": len(checks) + len(row_checks),
        "checks": checks,
        "row_checks": row_checks,
    }


def _nested_or_rfl(index: int, total: int) -> str:
    if total == 1:
        return "rfl"
    if index == 0:
        return "Or.inl rfl"
    expr = _nested_or_rfl(index - 1, total - 1)
    return f"Or.inr {expr}" if expr == "rfl" else f"Or.inr ({expr})"


def _support_disjunction(support: Sequence[int]) -> str:
    head, *tail = support
    expression = f"p = {head}"
    for value in tail:
        expression = f"{expression} ∨ p = {value}"
    return expression


def _support_rcases_pattern(support: Sequence[int]) -> str:
    return " | ".join("rfl" for _ in support)


def _support_hp_pattern(support: Sequence[int]) -> str:
    return " | ".join("hp_eq" for _ in support)


def _direct_prime_support_proof_diagnostics(spec: Mapping[str, Any]) -> dict[str, Any]:
    if not spec.get("support_target"):
        return {
            "support_target": None,
            "support_target_naming_style": "kernel_shared_or_not_emitted",
            "support_target_naming_policy": spec.get(
                "support_target_naming_policy",
                "kernel_shared_or_not_emitted",
            ),
            "support_proof_style": "not_emitted",
            "support_proof_case_count": 0,
            "old_interval_case_count_avoided": 0,
            "support_size": len(spec.get("support", [])),
            "interval_cases_L_limit": DIRECT_PRIME_SUPPORT_INTERVAL_CASES_L_LIMIT,
        }
    L = int(spec["L"])
    style = (
        "interval_cases"
        if L <= DIRECT_PRIME_SUPPORT_INTERVAL_CASES_L_LIMIT
        else "finset_equality"
    )
    return {
        "support_target": str(spec["support_target"]),
        "support_target_naming_style": (
            _direct_prime_certificate_support_target_style(spec)
        ),
        "support_target_naming_policy": spec.get(
            "support_target_naming_policy",
            _direct_prime_certificate_support_target_style(spec),
        ),
        "support_proof_style": style,
        "support_proof_case_count": L if style == "interval_cases" else 0,
        "old_interval_case_count_avoided": 0 if style == "interval_cases" else L,
        "support_size": len(spec.get("support", [])),
        "interval_cases_L_limit": DIRECT_PRIME_SUPPORT_INTERVAL_CASES_L_LIMIT,
    }


def _render_direct_prime_support_theorem_interval_cases(
    spec: Mapping[str, Any],
) -> str:
    support_target = spec.get("support_target")
    if not support_target:
        return ""
    L = int(spec["L"])
    support = [int(value) for value in spec["support"]]
    lines = [
        f"theorem {support_target}",
        "    {p : Nat}",
        f"    (hp : p ∈ ({L} : Nat).factorization.support) :",
        f"    {_support_disjunction(support)} := by",
        "  rw [Nat.support_factorization] at hp",
        "  have hp_prime : Nat.Prime p := Nat.prime_of_mem_primeFactors hp",
        f"  have hp_dvd : p ∣ {L} := (Nat.mem_primeFactors.mp hp).2.1",
        f"  have hp_le : p ≤ {L} := Nat.le_of_dvd (by decide : 0 < {L}) hp_dvd",
        "  have hp_pos : 0 < p := hp_prime.pos",
        "  interval_cases p",
    ]
    for value in range(1, L + 1):
        if value in support:
            lines.append(
                f"  · exact {_nested_or_rfl(support.index(value), len(support))}"
            )
        elif _is_prime_small(value):
            lines.append(
                f"  · exact False.elim ((by decide : ¬ {value} ∣ {L}) hp_dvd)"
            )
        else:
            lines.append(
                f"  · exact False.elim ((by decide : ¬ Nat.Prime {value}) hp_prime)"
            )
    return "\n".join(lines)


def _lean_nat_factor_term(prime: int, exponent: int) -> str:
    if exponent == 1:
        return str(prime)
    return f"({prime} ^ {exponent})"


def _right_nested_product(terms: Sequence[str]) -> str:
    if not terms:
        return "1"
    if len(terms) == 1:
        return terms[0]
    return f"{terms[0]} * ({_right_nested_product(terms[1:])})"


def _render_support_factorization_equality_proof(L: int) -> list[str]:
    factors = _factorint_small(L)
    terms = [
        _lean_nat_factor_term(prime, exponent)
        for prime, exponent in sorted(factors.items())
    ]
    lines = [
        "    rw [Nat.support_factorization]",
        f"    rw [show ({L} : Nat) = {_right_nested_product(terms)} by decide]",
    ]
    for _ in range(max(len(terms) - 1, 0)):
        lines.append("    rw [Nat.primeFactors_mul (by decide) (by decide)]")
    for prime, exponent in sorted(factors.items()):
        if exponent == 1:
            lines.append(
                f"    rw [Nat.Prime.primeFactors (by decide : Nat.Prime {prime})]"
            )
        else:
            lines.append(
                f"    rw [Nat.primeFactors_prime_pow (by decide : {exponent} ≠ 0) "
                f"(by decide : Nat.Prime {prime})]"
            )
    lines.append("    rfl")
    return lines


def _render_direct_prime_support_theorem_finset_equality(
    spec: Mapping[str, Any],
) -> str:
    support_target = spec.get("support_target")
    if not support_target:
        return ""
    L = int(spec["L"])
    support = [int(value) for value in spec["support"]]
    support_literal = ", ".join(str(value) for value in support)
    lines = [
        f"theorem {support_target}",
        "    {p : Nat}",
        f"    (hp : p ∈ ({L} : Nat).factorization.support) :",
        f"    {_support_disjunction(support)} := by",
        "  have hsupport :",
        f"      ({L} : Nat).factorization.support = ({{{support_literal}}} : Finset Nat) := by",
        *_render_support_factorization_equality_proof(L),
        "  rw [hsupport] at hp",
        "  simpa using hp",
    ]
    return "\n".join(lines)


def _render_direct_prime_support_theorem(spec: Mapping[str, Any]) -> str:
    diagnostics = _direct_prime_support_proof_diagnostics(spec)
    if diagnostics["support_proof_style"] == "finset_equality":
        return _render_direct_prime_support_theorem_finset_equality(spec)
    return _render_direct_prime_support_theorem_interval_cases(spec)


def _direct_prime_support_proof_check(spec: Mapping[str, Any]) -> dict[str, Any]:
    diagnostics = _direct_prime_support_proof_diagnostics(spec)
    rendered = _render_direct_prime_support_theorem(spec)
    contains_interval_cases = "interval_cases p" in rendered
    contains_finset_equality = "factorization.support = (" in rendered
    style = diagnostics["support_proof_style"]
    ok = (
        style == "not_emitted"
        or (style == "interval_cases" and contains_interval_cases)
        or (
            style == "finset_equality"
            and not contains_interval_cases
            and contains_finset_equality
        )
    )
    return {
        "spec_id": spec["spec_id"],
        "status": "PASS" if ok else "FAIL",
        "support_render_contains_interval_cases": contains_interval_cases,
        "support_render_contains_finset_equality": contains_finset_equality,
        **diagnostics,
    }


def _render_change_unit_power(b: int, Q: int, L: int) -> list[str]:
    if len(str(Q)) >= 7:
        return [
            f"      change (((ZMod.unitOfCoprime {b} hcop : (ZMod {Q})ˣ) :",
            f"          ZMod {Q}) ^ {L}) =",
        ]
    return [
        f"      change (((ZMod.unitOfCoprime {b} hcop : (ZMod {Q})ˣ) : ZMod {Q}) ^ {L}) ="
    ]


def _render_factorization_exponent_proof_lines(
    *,
    theorem_name: str,
    value: int,
    q: int,
    exponent: int,
    reduced_cofactor: int,
    indent: str = "    ",
) -> list[str]:
    lines = [
        f"{indent}have {theorem_name} : ({value} : Nat).factorization {q} = {exponent} := by"
    ]
    if exponent == 0:
        lines.append(
            f"{indent}  exact Nat.factorization_eq_zero_of_not_dvd (by decide : ¬ {q} ∣ {value})"
        )
        return lines
    if exponent == 1:
        lines.extend(
            [
                f"{indent}  rw [show ({value} : Nat) = {q} * {reduced_cofactor} by decide]",
                f"{indent}  rw [Nat.factorization_mul (by decide) (by decide)]",
                f"{indent}  simp [",
                f"{indent}    Nat.Prime.factorization_self (by decide : Nat.Prime {q}),",
                f"{indent}    Nat.factorization_eq_zero_of_not_dvd (by decide : ¬ {q} ∣ {reduced_cofactor}),",
                f"{indent}  ]",
            ]
        )
        return lines
    lines.extend(
        [
            f"{indent}  rw [show ({value} : Nat) = {q} ^ {exponent} * {reduced_cofactor} by decide]",
            f"{indent}  rw [Nat.factorization_mul (by decide) (by decide)]",
            f"{indent}  change ({q} ^ {exponent} : Nat).factorization {q} + ({reduced_cofactor} : Nat).factorization {q} = {exponent}",
            f"{indent}  have hleft : ({q} ^ {exponent} : Nat).factorization {q} = {exponent} :=",
            f"{indent}    Nat.factorization_pow_self (by decide : Nat.Prime {q})",
            f"{indent}  have hright : ({reduced_cofactor} : Nat).factorization {q} = 0 :=",
            f"{indent}    Nat.factorization_eq_zero_of_not_dvd (by decide : ¬ {q} ∣ {reduced_cofactor})",
            f"{indent}  rw [hleft, hright]",
        ]
    )
    return lines


def _render_A_factorization_proof_lines(
    *,
    A: int,
    q: int,
    A_q_exp: int,
    indent: str = "    ",
) -> list[str]:
    if A_q_exp == 0:
        return [
            f"{indent}have hA_factor : ({A} : Nat).factorization {q} = 0 :=",
            f"{indent}  Nat.factorization_eq_zero_of_not_dvd (by decide : ¬ {q} ∣ {A})",
        ]
    if A == q and A_q_exp == 1:
        return [
            f"{indent}have hA_factor : ({A} : Nat).factorization {q} = 1 :=",
            f"{indent}  Nat.Prime.factorization_self (by decide : Nat.Prime {q})",
        ]
    q_power = q**A_q_exp
    reduced_A = A // q_power
    return _render_factorization_exponent_proof_lines(
        theorem_name="hA_factor",
        value=A,
        q=q,
        exponent=A_q_exp,
        reduced_cofactor=reduced_A,
        indent=indent,
    )


def _render_prime_interval_proof_lines(q: int, indent: str = "    ") -> list[str]:
    sqrt_bound = math.isqrt(q)
    sqrt_succ = sqrt_bound + 1
    lines = [
        f"{indent}rw [Nat.prime_def_le_sqrt]",
        f"{indent}constructor",
        f"{indent}· decide",
        f"{indent}· intro m hm_ge hm_le hdiv",
        f"{indent}  have hm_le{sqrt_bound} : m ≤ {sqrt_bound} := by",
        f"{indent}    have hsqrt_lt : Nat.sqrt {q} < {sqrt_succ} :=",
        f"{indent}      (Nat.sqrt_lt'.2 (by decide : {q} < {sqrt_succ} ^ 2))",
        f"{indent}    exact Nat.le_of_lt_succ (lt_of_le_of_lt hm_le hsqrt_lt)",
        f"{indent}  interval_cases m",
    ]
    for value in range(2, sqrt_bound + 1):
        lines.append(
            f"{indent}  · exact (by decide : ¬ {value} ∣ {q}) hdiv"
        )
    return lines


def _direct_prime_row_uses_prime_power_helper(row: Mapping[str, Any]) -> bool:
    return (
        row.get("prime_witness_proof_strategy")
        == DIRECT_PRIME_HUGE_WITNESS_PROOF_STRATEGY
    )


def _render_direct_prime_certificate_lean_block(spec: Mapping[str, Any]) -> str:
    prefix = str(spec["case_prefix"])
    L = int(spec["L"])
    A = int(spec["A"])
    b = int(spec["b"])
    B = int(spec["B"])
    Q = int(spec["Q"])
    support = [int(value) for value in spec["support"]]
    support_target = str(
        spec.get("support_target", f"concrete_generated_b{b}_F{L}_factorization_support_cases")
    )
    blocks: list[str] = []
    support_block = _render_direct_prime_support_theorem(spec)
    if support_block:
        blocks.append(support_block)
    for row in spec["rows"]:
        p = int(row["p"])
        q = int(row["q"])
        quotient = int(row["component_quotient"])
        quotient_q_exp = int(
            row.get(
                "q_factorization_exponent",
                _factorization_exponent(quotient, q),
            )
        )
        A_q_exp = int(
            row.get(
                "A_q_factorization_exponent",
                _factorization_exponent(A, q),
            )
        )
        q_power = q**quotient_q_exp
        reduced_cofactor = int(
            row.get(
                "reduced_cofactor",
                quotient // q_power if q_power else row.get("cofactor", 0),
            )
        )
        cofactor = int(row["cofactor"]) if "cofactor" in row else reduced_cofactor
        theorem_lines: list[str] = []
        if row.get("set_option_max_rec_depth"):
            theorem_lines.append(
                f"set_option maxRecDepth {int(row['set_option_max_rec_depth'])} in"
            )
        if _direct_prime_row_uses_prime_power_helper(row):
            theorem_lines.extend(
                [
                    f"theorem {prefix}_p{p}_prime_witness :",
                    f"    PrimeComponentWitness {L} {A} {b} {p} {q} := by",
                    f"  have hq_prime : Nat.Prime {q} := by",
                    *_render_prime_interval_proof_lines(q),
                    *_render_A_factorization_proof_lines(
                        A=A,
                        q=q,
                        A_q_exp=A_q_exp,
                        indent="  ",
                    ),
                    "  exact primeComponentWitness_of_prime_power_cofactor",
                    f"    {L} {A} {b} {p} {q} {quotient} {quotient_q_exp} {reduced_cofactor} {A_q_exp}",
                    "    hq_prime",
                    "    (by decide)",
                    "    (by decide)",
                    "    (by decide)",
                    "    hA_factor",
                    "    (by decide)",
                ]
            )
        else:
            theorem_lines.extend(
                [
                    f"theorem {prefix}_p{p}_prime_witness :",
                    f"    PrimeComponentWitness {L} {A} {b} {p} {q} := by",
                    f"  refine ⟨(by decide : Nat.Prime {q}), ?_, ?_⟩",
                    f"  · have hquot : primeComponentQuotient {b} {L} {p} = {quotient} := by decide",
                    "    rw [hquot]",
                    "    decide",
                    f"  · have hquot : primeComponentQuotient {b} {L} {p} = {quotient} := by decide",
                    "    rw [hquot]",
                    *_render_factorization_exponent_proof_lines(
                        theorem_name="hfactor",
                        value=quotient,
                        q=q,
                        exponent=quotient_q_exp,
                        reduced_cofactor=cofactor
                        if quotient_q_exp == 1
                        else reduced_cofactor,
                    ),
                    "    rw [hfactor]",
                    *_render_A_factorization_proof_lines(A=A, q=q, A_q_exp=A_q_exp),
                    "    rw [hA_factor]",
                    "    decide",
                ]
            )
        blocks.append("\n".join(theorem_lines))
        blocks.append(
            "\n".join(
                [
                    f"theorem {prefix}_p{p}_CanonicalWitnessRowCase :",
                    f"    CanonicalWitnessRowCase {L} {A} {b} {p} := by",
                    f"  exact Or.inr (Or.inr ⟨{q}, {prefix}_p{p}_prime_witness⟩)",
                ]
            )
        )
    support_cover_lines = [
        "  covers_factor_support := by",
        "    intro p hp",
    ]
    if len(support) == 1:
        support_cover_lines.extend(
            [
                f"    rcases {support_target} hp with rfl",
                "    simp",
            ]
        )
    else:
        support_cover_lines.extend(
            [
                f"    rcases {support_target} hp with {_support_rcases_pattern(support)} <;>",
                "      simp",
            ]
        )
    certificate_lines = [
        f"def {spec['certificate']} :",
        f"    EmittedCertificateTable {L} {A} {b} where",
        f"  rows := ({{{', '.join(str(value) for value in support)}}} : Finset Nat)",
        "  L_ne_zero := by decide",
        *support_cover_lines,
        "  row_sound := by",
        "    intro p hp",
        "    simp at hp",
        f"    rcases hp with {_support_hp_pattern(support)}",
    ]
    for row in spec["rows"]:
        p = int(row["p"])
        certificate_lines.extend(
            [
                "    · subst p",
                "      exact EmittedGeneratedRowCase.prime_witness",
                f"        {prefix}_p{p}_prime_witness",
            ]
        )
    blocks.append("\n".join(certificate_lines))
    period_lines: list[str] = []
    if len(str(Q)) >= DIRECT_PRIME_LARGE_ROW_DIGITS:
        period_lines.append(
            f"set_option maxRecDepth {DIRECT_PRIME_LARGE_ROW_MAX_REC_DEPTH} in"
        )
    period_lines.extend([
        f"theorem {spec['period_target']} :",
        f"    orderOf (ZMod.unitOfCoprime {b}",
        f"      (by decide : Nat.Coprime {b} {Q})) = {L} := by",
        f"  let hcop : Nat.Coprime {b} {Q} := by decide",
        f"  have h_ord_dvd_L : orderOf (ZMod.unitOfCoprime {b} hcop) ∣ {L} := by",
        f"    have hpow_unit : (ZMod.unitOfCoprime {b} hcop) ^ {L} = 1 := by",
        "      apply Units.ext",
        *_render_change_unit_power(b, Q, L),
        f"        (1 : ZMod {Q})",
        "      rw [ZMod.coe_unitOfCoprime]",
        "      decide",
        "    exact (orderOf_dvd_iff_pow_eq_one).2 hpow_unit",
        "  exact finite_period_noncollapse_from_emitted_certificate_table",
        f"    {L} {A} {B} {Q} {b} hcop",
        "    (by decide)",
        "    (by decide)",
        "    h_ord_dvd_L",
        "    (by decide)",
        "    (by decide)",
        "    (by decide)",
        f"    (Nat.one_le_pow (orderOf (ZMod.unitOfCoprime {b} hcop)) {b} (by decide))",
        f"    {spec['certificate']}",
    ])
    blocks.append("\n".join(period_lines))
    return "\n\n".join(blocks)


def _direct_prime_lean_sources_by_path(
    lean_sources: Mapping[str, str] | str,
) -> dict[str, str]:
    if isinstance(lean_sources, str):
        return {DIRECT_PRIME_KERNEL_LEAN_MODULE.as_posix(): lean_sources}
    return {str(path): source for path, source in lean_sources.items()}


def _direct_prime_certificate_lean_emission_check(
    spec: Mapping[str, Any],
    lean_sources: Mapping[str, str] | str,
) -> dict[str, Any]:
    spec_validation = _direct_prime_certificate_spec_validation(spec)
    rendered = _render_direct_prime_certificate_lean_block(spec)
    rendered_support = _render_direct_prime_support_theorem(spec)
    support_proof = _direct_prime_support_proof_diagnostics(spec)
    target_ids = _direct_prime_certificate_target_ids(spec)
    lean_sources_by_path = _direct_prime_lean_sources_by_path(lean_sources)
    lean_module_path = _direct_prime_certificate_lean_module_path_string(spec)
    expected_source = lean_sources_by_path.get(lean_module_path, "")
    wrong_sources = {
        path: source
        for path, source in lean_sources_by_path.items()
        if path != lean_module_path
    }
    missing_declarations = [
        target_id
        for target_id in target_ids
        if f"theorem {target_id}" not in expected_source
        and f"def {target_id}" not in expected_source
    ]
    wrong_module_declarations = [
        {
            "target_id": target_id,
            "lean_module_path": path,
        }
        for target_id in target_ids
        for path, source in wrong_sources.items()
        if f"theorem {target_id}" in source or f"def {target_id}" in source
    ]
    rendered_block_present = rendered in expected_source
    wrong_module_present = any(rendered in source for source in wrong_sources.values()) or bool(
        wrong_module_declarations
    )
    status = (
        "wrong_module_declarations_present"
        if wrong_module_declarations
        else "rendered_lean_block_present"
        if rendered_block_present
        else "declaration_names_present_rendered_block_differs"
        if not missing_declarations
        else "missing_declarations"
    )
    issues: list[str] = []
    if spec_validation["status"] != "PASS":
        issues.extend(
            f"spec_validation:{issue}" for issue in spec_validation["issues"]
        )
    if wrong_module_declarations:
        issues.append("wrong_module_declarations_present")
    if missing_declarations:
        issues.append("missing_declarations")
    if status == "declaration_names_present_rendered_block_differs":
        issues.append("rendered_block_differs_from_expected")
    return {
        "spec_id": spec["spec_id"],
        "status": status,
        "issue_count": len(issues),
        "issues": issues,
        "spec_validation_status": spec_validation["status"],
        "spec_validation_issue_count": spec_validation["issue_count"],
        "spec_validation_issues": spec_validation["issues"],
        "spec_validation_check_count": spec_validation["check_count"],
        "support_proof_style": support_proof["support_proof_style"],
        "support_target_naming_style": support_proof[
            "support_target_naming_style"
        ],
        "support_target_naming_policy": support_proof[
            "support_target_naming_policy"
        ],
        "support_proof_case_count": support_proof["support_proof_case_count"],
        "old_interval_case_count_avoided": support_proof[
            "old_interval_case_count_avoided"
        ],
        "support_render_contains_interval_cases": "interval_cases p"
        in rendered_support,
        "lean_module_path": lean_module_path,
        "rendered_block_present": rendered_block_present,
        "wrong_module_present": wrong_module_present,
        "wrong_module_declaration_count": len(wrong_module_declarations),
        "wrong_module_declarations": wrong_module_declarations,
        "missing_declarations": missing_declarations,
        "rendered_block_sha256": f"sha256:{hashlib.sha256(rendered.encode('utf-8')).hexdigest()}",
        "target_ids": target_ids,
    }


def _direct_prime_generated_module_specs() -> list[Mapping[str, Any]]:
    if DIRECT_PRIME_GENERATED_MODULE_POLICY == "all_direct_prime_specs":
        return list(EMITTED_CERTIFICATE_DIRECT_PRIME_SPECS)
    raise ValueError(
        f"unsupported direct-prime generated module policy: {DIRECT_PRIME_GENERATED_MODULE_POLICY}"
    )


def _direct_prime_generated_module_aggregate_specs() -> list[Mapping[str, Any]]:
    return [
        spec
        for spec in _direct_prime_generated_module_specs()
        if _direct_prime_certificate_lean_module_path(spec)
        == DIRECT_PRIME_GENERATED_LEAN_MODULE
    ]


def _direct_prime_generated_certificate_shard_specs() -> dict[str, list[Mapping[str, Any]]]:
    shards: dict[str, list[Mapping[str, Any]]] = {
        spec_id: []
        for spec_id in DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_SPEC_IDS
    }
    for spec in _direct_prime_generated_module_specs():
        spec_id = str(spec["spec_id"])
        if spec_id in shards:
            shards[spec_id].append(spec)
    return shards


def _direct_prime_certificate_table_kernel_role_text() -> str:
    generated_specs = _direct_prime_generated_module_specs()
    spec_refs = ", ".join(
        f"{spec['spec_id']} (Q={spec['Q']})" for spec in generated_specs
    )
    return (
        "Projects family-tagged emitted generated rows into CanonicalWitnessRowCase, "
        "packages support tables as EmittedCertificateTable, and exercises the "
        "certificate-table period route over the direct-prime generated semantic "
        f"spec registry: {spec_refs}."
    )


def _render_direct_prime_generated_certificates_module_body(
    *,
    specs: Sequence[Mapping[str, Any]],
    imports: Sequence[str],
    lift_blocks: Sequence[str] = (),
    header: str,
) -> str:
    blocks = [
        _render_direct_prime_certificate_lean_block(spec)
        for spec in specs
    ]
    import_lines = [f"import {module}" for module in imports]
    return "\n".join(
        [
            header,
            *import_lines,
            "",
            "set_option linter.unusedTactic false",
            "set_option linter.unreachableTactic false",
            "",
            "namespace Erdos257PeriodNoncollapse",
            "",
            "\n\n".join([*blocks, *lift_blocks]),
            "",
            "end Erdos257PeriodNoncollapse",
            "",
        ]
    )


def _render_direct_prime_generated_certificate_shard_module(spec_id: str) -> str:
    shard_specs = _direct_prime_generated_certificate_shard_specs().get(spec_id, [])
    return _render_direct_prime_generated_certificates_module_body(
        specs=shard_specs,
        imports=["Erdos257PeriodNoncollapse.CertificateKernel"],
        header=f"-- Generated direct-prime emitted certificate shard: {spec_id}.",
    )


def _render_direct_prime_generated_certificates_modules() -> dict[str, str]:
    shard_modules = {
        path.as_posix(): _render_direct_prime_generated_certificate_shard_module(spec_id)
        for spec_id, path in DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_MODULES.items()
    }
    shard_imports = [
        _lean_import_from_module_path(path)
        for path in DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_MODULES.values()
    ]
    aggregate = _render_direct_prime_generated_certificates_module_body(
        specs=_direct_prime_generated_module_aggregate_specs(),
        imports=[
            "Erdos257PeriodNoncollapse.CertificateKernel",
            *shard_imports,
        ],
        lift_blocks=_render_direct_prime_denominator_invisible_lift_lean_blocks(),
        header="-- Generated direct-prime emitted certificate aggregate.",
    )
    return {
        DIRECT_PRIME_GENERATED_LEAN_MODULE.as_posix(): aggregate,
        **shard_modules,
    }


def _render_direct_prime_generated_certificates_module() -> str:
    return _render_direct_prime_generated_certificates_modules()[
        DIRECT_PRIME_GENERATED_LEAN_MODULE.as_posix()
    ]


def _direct_prime_refresh_spec_globals() -> None:
    global EMITTED_CERTIFICATE_DIRECT_PRIME_SPECS
    global EMITTED_CERTIFICATE_DIRECT_PRIME_AUTOFILL_CHECKS
    global EMITTED_CERTIFICATE_DIRECT_PRIME_AUTOFILL_STATUS
    global EMITTED_CERTIFICATE_DIRECT_PRIME_SPEC_BY_ID

    EMITTED_CERTIFICATE_DIRECT_PRIME_SPECS = (
        _dedupe_direct_prime_certificate_support_targets(
            [
                _normalize_direct_prime_certificate_spec(spec)
                for spec in EMITTED_CERTIFICATE_DIRECT_PRIME_SPEC_INPUTS
            ]
        )
    )
    EMITTED_CERTIFICATE_DIRECT_PRIME_AUTOFILL_CHECKS = [
        _direct_prime_certificate_explicit_field_drift_check(raw_spec, normalized_spec)
        for raw_spec, normalized_spec in zip(
            EMITTED_CERTIFICATE_DIRECT_PRIME_SPEC_INPUTS,
            EMITTED_CERTIFICATE_DIRECT_PRIME_SPECS,
            strict=True,
        )
    ]
    EMITTED_CERTIFICATE_DIRECT_PRIME_AUTOFILL_STATUS = (
        "PASS"
        if all(
            check["status"] == "PASS"
            for check in EMITTED_CERTIFICATE_DIRECT_PRIME_AUTOFILL_CHECKS
        )
        else "FAIL"
    )
    EMITTED_CERTIFICATE_DIRECT_PRIME_SPEC_BY_ID = {
        spec["spec_id"]: spec for spec in EMITTED_CERTIFICATE_DIRECT_PRIME_SPECS
    }


def _direct_prime_generated_module_canonical_check(
    lean_sources: Mapping[str, str],
) -> dict[str, Any]:
    canonical_modules = _render_direct_prime_generated_certificates_modules()
    aggregate_path = DIRECT_PRIME_GENERATED_LEAN_MODULE.as_posix()
    canonical = canonical_modules[aggregate_path]
    actual = lean_sources.get(aggregate_path, "")
    generated_specs = _direct_prime_generated_module_specs()
    generated_module_target_ids = [
        target_id
        for spec in generated_specs
        for target_id in _direct_prime_certificate_target_ids(spec)
    ]
    lift_registry = _direct_prime_denominator_invisible_lift_registry()
    lift_target_ids = [
        target_id
        for binding in lift_registry["bindings"]
        for target_id in binding["target_ids"]
    ]
    generated_module_target_ids.extend(lift_target_ids)
    duplicate_target_ids = sorted(
        {
            target_id
            for target_id in generated_module_target_ids
            if generated_module_target_ids.count(target_id) > 1
        }
    )
    issues: list[str] = []
    module_rows: list[dict[str, Any]] = []
    for module_path, canonical_source in canonical_modules.items():
        actual_source = lean_sources.get(module_path, "")
        module_issues = []
        if actual_source != canonical_source:
            module_issues.append("actual_differs_from_canonical")
        module_rows.append(
            {
                "module_path": module_path,
                "status": "PASS" if not module_issues else "FAIL",
                "issues": module_issues,
                "canonical_sha256": f"sha256:{hashlib.sha256(canonical_source.encode('utf-8')).hexdigest()}",
                "actual_sha256": f"sha256:{hashlib.sha256(actual_source.encode('utf-8')).hexdigest()}",
                "canonical_byte_count": len(canonical_source.encode("utf-8")),
                "actual_byte_count": len(actual_source.encode("utf-8")),
            }
        )
    if any(row["status"] != "PASS" for row in module_rows):
        issues.append("generated_module_actual_differs_from_canonical")
    if duplicate_target_ids:
        issues.append("generated_module_duplicate_target_ids")
    if lift_registry["status"] != "PASS":
        issues.append("generated_module_lift_registry_failed")
    return {
        "status": (
            "PASS"
            if all(row["status"] == "PASS" for row in module_rows)
            and not duplicate_target_ids
            and lift_registry["status"] == "PASS"
            else "FAIL"
        ),
        "issue_count": len(issues),
        "issues": issues,
        "generated_module_path": aggregate_path,
        "generated_module_rendered_from_specs": True,
        "generated_module_spec_count": len(generated_specs),
        "generated_module_target_count": len(generated_module_target_ids),
        "generated_module_lift_binding_count": lift_registry["binding_count"],
        "generated_module_lift_target_count": len(lift_target_ids),
        "generated_module_duplicate_target_id_count": len(duplicate_target_ids),
        "generated_module_duplicate_target_ids": duplicate_target_ids,
        "generated_module_canonical_sha256": f"sha256:{hashlib.sha256(canonical.encode('utf-8')).hexdigest()}",
        "generated_module_actual_sha256": f"sha256:{hashlib.sha256(actual.encode('utf-8')).hexdigest()}",
        "generated_module_canonical_byte_count": len(canonical.encode("utf-8")),
        "generated_module_actual_byte_count": len(actual.encode("utf-8")),
        "generated_module_shard_count": len(DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_MODULES),
        "generated_module_shard_spec_ids": list(
            DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_SPEC_IDS
        ),
        "generated_module_shards": [
            {
                "spec_id": spec_id,
                "module_path": path.as_posix(),
                "module_import": _lean_import_from_module_path(path),
            }
            for spec_id, path in DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_MODULES.items()
        ],
        "generated_module_canonical_modules": module_rows,
    }


def _period_theorem_region(rendered: str, period_target: str) -> str:
    marker = f"theorem {period_target}"
    start = rendered.find(marker)
    return rendered[start:] if start >= 0 else ""


def _direct_prime_period_base_generality_check(
    spec: Mapping[str, Any],
    rendered: str | None = None,
) -> dict[str, Any]:
    b = int(spec["b"])
    Q = int(spec["Q"])
    rendered = rendered if rendered is not None else _render_direct_prime_certificate_lean_block(spec)
    period_region = _period_theorem_region(rendered, str(spec["period_target"]))
    is_composite_base = b > 1 and not _is_prime_small(b)
    expected_fragments = [
        f"ZMod.unitOfCoprime {b}",
        f"Nat.Coprime {b} {Q}",
        f"{spec['L']} {spec['A']} {spec['B']} {Q} {b} hcop",
        f"Nat.one_le_pow (orderOf (ZMod.unitOfCoprime {b} hcop)) {b}",
    ]
    missing_expected_fragments = [
        fragment for fragment in expected_fragments if fragment not in period_region
    ]
    forbidden_base_values = []
    if b != 2:
        forbidden_base_values.append(2)
    if is_composite_base and b != 3:
        forbidden_base_values.append(3)
    forbidden_fragments_by_base = {
        forbidden_base: [
            f"ZMod.unitOfCoprime {forbidden_base}",
            f"Nat.Coprime {forbidden_base} {Q}",
            (
                "Nat.one_le_pow (orderOf "
                f"(ZMod.unitOfCoprime {forbidden_base} hcop)) {forbidden_base}"
            ),
        ]
        for forbidden_base in forbidden_base_values
    }
    forbidden_base_fragment_hits = [
        fragment
        for fragments in forbidden_fragments_by_base.values()
        for fragment in fragments
        if fragment in period_region
    ]
    forbidden_b2_fragment_hits = [
        fragment
        for fragment in forbidden_fragments_by_base.get(2, [])
        if fragment in period_region
    ]
    status = (
        "PASS"
        if period_region
        and not missing_expected_fragments
        and not forbidden_base_fragment_hits
        else "FAIL"
    )
    issues: list[str] = []
    if not period_region:
        issues.append("period_region_missing")
    if missing_expected_fragments:
        issues.append("period_base_expected_fragments_missing")
    if forbidden_base_fragment_hits:
        issues.append("period_base_forbidden_fragments_present")
    return {
        "spec_id": spec["spec_id"],
        "status": status,
        "issue_count": len(issues),
        "issues": issues,
        "generated_period_base": b,
        "is_composite_base": is_composite_base,
        "period_target": spec["period_target"],
        "period_region_present": bool(period_region),
        "missing_expected_fragments": missing_expected_fragments,
        "forbidden_b2_fragment_hits": forbidden_b2_fragment_hits,
        "forbidden_base_fragment_hits": forbidden_base_fragment_hits,
        "period_base_hardcoding_check": status,
    }


def _direct_prime_base_generality_check(
    specs: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    non_b2_specs = [spec for spec in specs if int(spec["b"]) != 2]
    period_checks = [
        _direct_prime_period_base_generality_check(spec) for spec in non_b2_specs
    ]
    status = "PASS" if all(check["status"] == "PASS" for check in period_checks) else "FAIL"
    return {
        "status": status,
        "non_b2_generated_spec_count": len(non_b2_specs),
        "latest_non_b2_generated_spec": non_b2_specs[-1]["spec_id"]
        if non_b2_specs
        else None,
        "generated_period_base": int(non_b2_specs[-1]["b"])
        if non_b2_specs
        else None,
        "period_base_hardcoding_check": status,
        "period_checks": period_checks,
    }


def _direct_prime_composite_base_generality_check(
    specs: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    composite_base_specs = [
        spec
        for spec in specs
        if int(spec["b"]) > 1 and not _is_prime_small(int(spec["b"]))
    ]
    period_checks = [
        _direct_prime_period_base_generality_check(spec)
        for spec in composite_base_specs
    ]
    status = "PASS" if all(check["status"] == "PASS" for check in period_checks) else "FAIL"
    return {
        "status": status,
        "composite_base_generated_spec_count": len(composite_base_specs),
        "latest_composite_base_generated_spec": (
            composite_base_specs[-1]["spec_id"] if composite_base_specs else None
        ),
        "generated_period_base": int(composite_base_specs[-1]["b"])
        if composite_base_specs
        else None,
        "period_base_hardcoding_check": status,
        "period_checks": period_checks,
    }


def _direct_prime_multi_digit_base_generality_check(
    specs: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    multi_digit_base_specs = [spec for spec in specs if int(spec["b"]) >= 10]
    period_checks = [
        _direct_prime_period_base_generality_check(spec)
        for spec in multi_digit_base_specs
    ]
    status = "PASS" if all(check["status"] == "PASS" for check in period_checks) else "FAIL"
    return {
        "status": status,
        "multi_digit_base_generated_spec_count": len(multi_digit_base_specs),
        "latest_multi_digit_base_generated_spec": (
            multi_digit_base_specs[-1]["spec_id"]
            if multi_digit_base_specs
            else None
        ),
        "generated_period_base": int(multi_digit_base_specs[-1]["b"])
        if multi_digit_base_specs
        else None,
        "period_base_hardcoding_check": status,
        "period_checks": period_checks,
    }


def _direct_prime_certificate_milestone(spec: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "spec_id": spec["spec_id"],
        "certificate": spec["certificate"],
        "period_target": spec["period_target"],
        "b": spec["b"],
        "L": spec["L"],
        "A": spec["A"],
        "B": spec["B"],
        "Q": spec["Q"],
        "support": spec["support"],
        "role": spec["role"],
        "target_ids": _direct_prime_certificate_target_ids(spec),
        "next_target": spec["next_target"],
    }


def _is_direct_prime_certificate_milestone(
    milestone: Mapping[str, Any] | None,
) -> bool:
    return bool(milestone and "spec_id" in milestone)


def _direct_prime_support_text(milestone: Mapping[str, Any]) -> str:
    return "{" + ",".join(str(value) for value in milestone["support"]) + "}"


def _direct_prime_next_action_text(target: str) -> str:
    if target == DIRECT_PRIME_DENOMINATOR_LATTICE_EXHAUSTED_NEXT_FOCUS:
        return "Broaden the denominator-lattice scout or select the next generated family."
    return f"Bind {target}."


def _direct_prime_lead_projection(
    milestone: Mapping[str, Any] | None,
) -> dict[str, Any] | None:
    if not _is_direct_prime_certificate_milestone(milestone):
        return None
    role = str(milestone["role"])
    next_target = str(milestone["next_target"])
    level = str(milestone.get("verified_level", "pending"))
    spec_id = str(milestone["spec_id"])
    q_value = int(milestone["Q"])
    support_text = _direct_prime_support_text(milestone)
    next_text = next_target.replace("_", " ")
    if level == "period":
        return {
            "proof_candidate_status": f"{role}_verified_pending_{next_target}",
            "lean_target_ladder_status": (
                f"microkernel_verified_{role}_pending_{next_target}"
            ),
            "certificate_kernel_status": (
                f"lean_{role}_period_target_verified_no_sorry_pending_{next_target}"
            ),
            "proof_kernel_route_status": (
                f"proof_kernel_split_{role}_verified_pending_{next_target}"
            ),
            "first_lean_target": next_target,
            "planned_theorem_id": milestone["period_target"],
            "planned_theorem_status": "lean_verified_no_sorry",
            "target_binding_status": (
                f"real_target_{role}_period_bound_to_lean_microkernel"
            ),
            "current_decisive_blocker": (
                f"The {spec_id} {role.replace('_', ' ')} certificate is verified "
                f"through Q={q_value} over support {support_text}; next {next_text}."
            ),
            "reason": (
                f"The generated-module spec-to-Lean emitter check now accounts for "
                f"the {spec_id} certificate with Q={q_value} over support "
                f"{support_text}; {next_text} remains the next target."
            ),
        }
    if level == "certificate":
        return {
            "proof_candidate_status": f"{role}_certificate_verified_pending_period_target",
            "lean_target_ladder_status": (
                f"microkernel_verified_{role}_certificate_pending_period_target"
            ),
            "certificate_kernel_status": (
                f"lean_{role}_certificate_verified_no_sorry_pending_period_target"
            ),
            "proof_kernel_route_status": (
                f"proof_kernel_split_{role}_pending_period_target"
            ),
            "first_lean_target": milestone["period_target"],
            "planned_theorem_id": milestone["certificate"],
            "planned_theorem_status": "lean_verified_no_sorry",
            "target_binding_status": (
                f"real_target_{role}_certificate_bound_to_lean_microkernel"
            ),
            "current_decisive_blocker": (
                f"The {spec_id} {role.replace('_', ' ')} certificate object is "
                "verified; next run it through "
                "finite_period_noncollapse_from_emitted_certificate_table."
            ),
            "reason": (
                f"The generated-module spec-to-Lean emitter check now accounts for "
                f"the {spec_id} certificate object; the period target remains "
                "pending."
            ),
        }
    return None


def _direct_prime_certificate_lean_targets(spec: Mapping[str, Any]) -> list[dict[str, Any]]:
    prefix = str(spec["case_prefix"])
    label = str(spec["spec_id"])
    row_targets: list[dict[str, Any]] = []
    support_targets: list[dict[str, Any]] = []
    if "support_target" in spec:
        support_targets.append(
            {
                "target_id": spec["support_target"],
                "target_kind": f"Lean {label} support eliminator",
                "statement_summary": (
                    f"Eliminate p in ({spec['L']}).factorization.support to the "
                    f"generated support cases {spec['support']}."
                ),
                "depends_on": [
                    "Nat.support_factorization",
                    "Nat.mem_primeFactors",
                ],
                "boundary": (
                    f"concrete {label} support eliminator only; no arbitrary support "
                    "coverage or generated-row existence claim"
                ),
            }
        )
    for row in spec["rows"]:
        p = row["p"]
        q = row["q"]
        prime_target = f"{prefix}_p{p}_prime_witness"
        row_targets.extend(
            [
                {
                    "target_id": prime_target,
                    "target_kind": f"Lean {label} p={p} direct witness",
                    "statement_summary": (
                        f"Bind the b={spec['b']}, L={spec['L']}, A={spec['A']}, "
                        f"p={p} row as a direct PrimeComponentWitness with q={q} "
                        f"after Q={spec['B']}/gcd({spec['A']},{spec['B']})={spec['Q']}."
                    ),
                    "depends_on": [
                        "PrimeComponentWitness",
                        "primeComponentQuotient",
                    ],
                    "boundary": (
                        f"single p={p} direct witness row in the concrete {label} "
                        "emitted certificate only; no arbitrary generated-row existence claim"
                    ),
                },
                {
                    "target_id": f"{prefix}_p{p}_CanonicalWitnessRowCase",
                    "target_kind": f"Lean {label} p={p} canonical row case",
                    "statement_summary": (
                        f"Promote the b={spec['b']}, L={spec['L']}, A={spec['A']}, "
                        f"p={p} direct witness row to CanonicalWitnessRowCase."
                    ),
                    "depends_on": [
                        "CanonicalWitnessRowCase",
                        prime_target,
                    ],
                    "boundary": (
                        f"single p={p} row-case adapter only; no finite certificate "
                        "or global existence claim"
                    ),
                },
            ]
        )
    return [
        *support_targets,
        *row_targets,
        {
            "target_id": spec["certificate"],
            "target_kind": f"Lean {label} emitted certificate fixture",
            "statement_summary": (
                f"Package the b={spec['b']}, L={spec['L']}, A={spec['A']} "
                f"support table {spec['support']} and direct prime-witness rows "
                "as an EmittedCertificateTable."
            ),
            "depends_on": [
                "EmittedCertificateTable",
                str(
                    spec.get(
                        "support_target",
                        _direct_prime_certificate_expected_names(spec)[
                            "support_target"
                        ],
                    )
                ),
                *[
                    f"{prefix}_p{row['p']}_prime_witness"
                    for row in spec["rows"]
                ],
            ],
            "boundary": (
                f"concrete {label} emitted certificate only; no arbitrary "
                "generated-row existence claim"
            ),
        },
        {
            "target_id": spec["period_target"],
            "target_kind": f"Lean {label} emitted certificate-table period target",
            "statement_summary": (
                f"Consume the named b={spec['b']}, L={spec['L']}, A={spec['A']} "
                f"emitted certificate table to prove orderOf({spec['b']} mod {spec['Q']})="
                f"{spec['L']}."
            ),
            "depends_on": [
                "finite_period_noncollapse_from_emitted_certificate_table",
                spec["certificate"],
            ],
            "boundary": (
                f"concrete {label} period target only; no arbitrary finite theorem "
                "or Erdos #257 claim"
            ),
        },
    ]


def _direct_prime_certificate_real_bindings(
    spec: Mapping[str, Any],
) -> list[dict[str, Any]]:
    prefix = str(spec["case_prefix"])
    label = str(spec["spec_id"])
    bindings: list[dict[str, Any]] = []
    if "support_target" in spec:
        bindings.append(
            {
                "target_id": str(spec["support_target"]),
                "status": "lean_verified_no_sorry",
                "claim_boundary": (
                    f"concrete {label} support eliminator only; no arbitrary support "
                    "coverage claim"
                ),
                "validation": "cd formal_math/erdos257_period_noncollapse && lake build",
                "prover_role": (
                    f"turns p in ({spec['L']}).factorization.support into the "
                    f"emitted support cases {spec['support']}"
                ),
            }
        )
    for row in spec["rows"]:
        p = row["p"]
        q = row["q"]
        bindings.extend(
            [
                {
                    "target_id": f"{prefix}_p{p}_prime_witness",
                    "status": "lean_verified_no_sorry",
                    "claim_boundary": (
                        f"single {label} p={p} direct prime-witness row only; "
                        "no arbitrary generated-row existence claim"
                    ),
                    "validation": "cd formal_math/erdos257_period_noncollapse && lake build",
                    "prover_role": (
                        f"binds the b={spec['b']}, L={spec['L']}, A={spec['A']}, "
                        f"p={p} row as a direct PrimeComponentWitness with q={q} "
                        f"under Q={spec['Q']}"
                    ),
                },
                {
                    "target_id": f"{prefix}_p{p}_CanonicalWitnessRowCase",
                    "status": "lean_verified_no_sorry",
                    "claim_boundary": (
                        f"single {label} p={p} canonical row-case adapter only; "
                        "no finite certificate or global existence claim"
                    ),
                    "validation": "cd formal_math/erdos257_period_noncollapse && lake build",
                    "prover_role": (
                        f"promotes the {label} p={p} direct prime witness into "
                        "CanonicalWitnessRowCase"
                    ),
                },
            ]
        )
    return [
        *bindings,
        {
            "target_id": spec["certificate"],
            "status": "lean_verified_no_sorry",
            "claim_boundary": (
                f"concrete {label} emitted certificate only; no arbitrary "
                "generated-row or Erdos #257 claim"
            ),
            "validation": "cd formal_math/erdos257_period_noncollapse && lake build",
            "prover_role": (
                f"packages the b={spec['b']}, L={spec['L']}, A={spec['A']} "
                f"support table {spec['support']} and direct prime-witness rows "
                "as an emitted certificate"
            ),
        },
        {
            "target_id": spec["period_target"],
            "status": "lean_verified_no_sorry",
            "claim_boundary": (
                f"concrete {label} period target only; no arbitrary finite theorem "
                "or Erdos #257 claim"
            ),
            "validation": "cd formal_math/erdos257_period_noncollapse && lake build",
            "prover_role": (
                f"runs the named {label} emitted certificate through "
                "finite_period_noncollapse_from_emitted_certificate_table to prove "
                f"orderOf({spec['b']} mod {spec['Q']})={spec['L']}"
            ),
        },
    ]


def _direct_prime_certificate_spec_projection(
    spec: Mapping[str, Any],
    verified_targets: Sequence[str],
    lean_source: Mapping[str, str] | str = "",
) -> dict[str, Any]:
    target_ids = _direct_prime_certificate_target_ids(spec)
    verified = set(verified_targets)
    verified_target_count = sum(1 for target_id in target_ids if target_id in verified)
    lean_emission = _direct_prime_certificate_lean_emission_check(spec, lean_source)
    proof_policy = _direct_prime_certificate_proof_policy_check(spec)
    return {
        "spec_id": spec["spec_id"],
        "b": spec["b"],
        "L": spec["L"],
        "A": spec["A"],
        "B": spec["B"],
        "Q": spec["Q"],
        "support": spec["support"],
        "rows": spec["rows"],
        "certificate": spec["certificate"],
        "period_target": spec["period_target"],
        "lean_module_path": lean_emission["lean_module_path"],
        "target_ids": target_ids,
        "verified_target_count": verified_target_count,
        "spec_validation_status": lean_emission["spec_validation_status"],
        "spec_validation_issue_count": lean_emission["spec_validation_issue_count"],
        "spec_validation_issues": lean_emission["spec_validation_issues"],
        "spec_validation_check_count": lean_emission["spec_validation_check_count"],
        "proof_policy_status": proof_policy["status"],
        "proof_policy": proof_policy,
        "factorization_backend": _direct_prime_factorization_backend_receipt()["backend"],
        "support_proof_style": lean_emission["support_proof_style"],
        "support_proof_case_count": lean_emission["support_proof_case_count"],
        "old_interval_case_count_avoided": lean_emission[
            "old_interval_case_count_avoided"
        ],
        "support_render_contains_interval_cases": lean_emission[
            "support_render_contains_interval_cases"
        ],
        "lean_emission_status": lean_emission["status"],
        "lean_emission_rendered_block_sha256": lean_emission["rendered_block_sha256"],
        "lean_emission_missing_declarations": lean_emission["missing_declarations"],
        "lean_emission_wrong_module_present": lean_emission["wrong_module_present"],
        "lean_emission_wrong_module_declaration_count": lean_emission[
            "wrong_module_declaration_count"
        ],
        "status": "lean_verified_no_sorry"
        if spec["period_target"] in verified
        else "certificate_verified_pending_period_target"
        if spec["certificate"] in verified
        else "pending_lean",
    }


def _direct_prime_generated_module_split_check(
    lean_sources: Mapping[str, str],
) -> dict[str, Any]:
    moved_specs = _direct_prime_generated_module_specs()
    moved_checks = [
        _direct_prime_certificate_lean_emission_check(spec, lean_sources)
        for spec in moved_specs
    ]
    canonical_check = _direct_prime_generated_module_canonical_check(lean_sources)
    generated_module_target_count = int(
        canonical_check["generated_module_target_count"]
    )
    kernel_contains_moved_blocks = any(
        check["wrong_module_declaration_count"] > 0 for check in moved_checks
    )
    generated_module_contains_moved_blocks = all(
        check["rendered_block_present"] for check in moved_checks
    )
    status = (
        "PASS"
        if generated_module_contains_moved_blocks
        and not kernel_contains_moved_blocks
        and canonical_check["status"] == "PASS"
        else "FAIL"
    )
    return {
        "status": status,
        "split_policy": "aggregator_imports_safe_generated_certificate_shards",
        "canonical_status": canonical_check["status"],
        "canonical_check": canonical_check,
        "generated_module_rendered_from_specs": canonical_check[
            "generated_module_rendered_from_specs"
        ],
        "generated_module_spec_count": canonical_check[
            "generated_module_spec_count"
        ],
        "generated_module_canonical_sha256": canonical_check[
            "generated_module_canonical_sha256"
        ],
        "moved_specs": [str(spec["spec_id"]) for spec in moved_specs],
        "generated_module_path": DIRECT_PRIME_GENERATED_LEAN_MODULE.as_posix(),
        "generated_module_shard_count": canonical_check[
            "generated_module_shard_count"
        ],
        "generated_module_shard_spec_ids": canonical_check[
            "generated_module_shard_spec_ids"
        ],
        "generated_module_shards": canonical_check["generated_module_shards"],
        "kernel_module_path": DIRECT_PRIME_KERNEL_LEAN_MODULE.as_posix(),
        "generated_module_target_count": generated_module_target_count,
        "generated_module_lift_binding_count": canonical_check[
            "generated_module_lift_binding_count"
        ],
        "generated_module_lift_target_count": canonical_check[
            "generated_module_lift_target_count"
        ],
        "kernel_contains_moved_blocks": kernel_contains_moved_blocks,
        "generated_module_contains_moved_blocks": generated_module_contains_moved_blocks,
        "moved_spec_checks": [
            {
                "spec_id": check["spec_id"],
                "lean_module_path": check["lean_module_path"],
                "rendered_block_present": check["rendered_block_present"],
                "wrong_module_present": check["wrong_module_present"],
                "wrong_module_declaration_count": check[
                    "wrong_module_declaration_count"
                ],
                "status": check["status"],
            }
            for check in moved_checks
        ],
    }


