def _direct_prime_frontier_split_wave_policy_check(
    *,
    repo_root: Path = REPO_ROOT,
) -> dict[str, Any]:
    persisted = _read_json_if_exists(
        FRONTIER_SPLIT_WAVE_POLICY_RECEIPT_PATH,
        repo_root=repo_root,
    )
    current = _direct_prime_frontier_split_wave_policy_receipt(repo_root=repo_root)
    issues = list(current.get("issues", []))
    if not persisted:
        issues.append(f"missing:{FRONTIER_SPLIT_WAVE_POLICY_RECEIPT_PATH.as_posix()}")
    elif persisted.get("schema_version") != (
        DIRECT_PRIME_FRONTIER_SPLIT_WAVE_POLICY_RECEIPT_SCHEMA_VERSION
    ):
        issues.append("split_wave_policy_schema_version_mismatch")
    else:
        comparable_keys = (
            "blocker_recommended_next_safe_action",
            "blocker_recommended_next_safe_candidate",
            "candidate_policy_class",
            "admission_status",
            "raw_bind_allowed",
            "recommended_next_safe_action",
        )
        for key in comparable_keys:
            if persisted.get(key) != current.get(key):
                issues.append(f"split_wave_policy_currentness_mismatch:{key}")
        persisted_candidate = persisted.get("candidate")
        current_candidate = current.get("candidate")
        if persisted_candidate != current_candidate:
            issues.append("split_wave_policy_currentness_mismatch:candidate")
        persisted_guard = persisted.get("invalid_lift_helper_guard")
        current_guard = current.get("invalid_lift_helper_guard")
        if persisted_guard != current_guard:
            issues.append(
                "split_wave_policy_currentness_mismatch:invalid_lift_helper_guard"
            )
    if current.get("raw_bind_allowed") is not False:
        issues.append("split_wave_policy_allows_raw_bind_without_guard")
    return {
        "schema_version": (
            DIRECT_PRIME_FRONTIER_SPLIT_WAVE_POLICY_RECEIPT_SCHEMA_VERSION
        ),
        "status": "PASS" if not issues else "FAIL",
        "issues": issues,
        "receipt_ref": FRONTIER_SPLIT_WAVE_POLICY_RECEIPT_PATH.as_posix(),
        "receipt_status": persisted.get("status") if persisted else None,
        "candidate": (
            (current.get("candidate") or {}).get("candidate_id")
            if isinstance(current.get("candidate"), Mapping)
            else None
        ),
        "candidate_policy_class": current.get("candidate_policy_class"),
        "admission_status": current.get("admission_status"),
        "raw_bind_allowed": current.get("raw_bind_allowed"),
        "recommended_next_safe_action": current.get("recommended_next_safe_action"),
        "blocker_recommended_next_safe_action": current.get(
            "blocker_recommended_next_safe_action"
        ),
        "layout_receipt_ref": FRONTIER_CONVEYOR_LAYOUT_RECEIPT_PATH.as_posix(),
        "claim_boundary": current.get("claim_boundary"),
    }


