MAX_SUBSET_SIZE = 5


def _repo_path(path: str | Path, *, repo_root: Path = REPO_ROOT) -> Path:
    candidate = Path(path)
    return candidate if candidate.is_absolute() else repo_root / candidate


def _repo_path_with_live_fallback(path: str | Path, *, repo_root: Path = REPO_ROOT) -> Path:
    target = _repo_path(path, repo_root=repo_root)
    if target.exists() or repo_root == REPO_ROOT:
        return target
    fallback = _repo_path(path, repo_root=REPO_ROOT)
    return fallback if fallback.exists() else target


def _read_direct_prime_lean_sources(*, repo_root: Path = REPO_ROOT) -> dict[str, str]:
    sources: dict[str, str] = {}
    for module_path in (
        DIRECT_PRIME_KERNEL_LEAN_MODULE,
        DIRECT_PRIME_GENERATED_LEAN_MODULE,
        *DIRECT_PRIME_GENERATED_CERTIFICATE_SHARD_MODULES.values(),
    ):
        path = _repo_path_with_live_fallback(module_path, repo_root=repo_root)
        sources[module_path.as_posix()] = (
            path.read_text(encoding="utf-8") if path.is_file() else ""
        )
    return sources


def _read_json_if_exists(path: str | Path, *, repo_root: Path = REPO_ROOT) -> dict[str, Any]:
    target = _repo_path(path, repo_root=repo_root)
    if not target.exists():
        return {}
    payload = json.loads(target.read_text(encoding="utf-8"))
    if not isinstance(payload, dict):
        raise ValueError(f"expected JSON object at {target}")
    return payload


def _target_runner_receipt_status(
    *,
    latest_real_target_binding: Mapping[str, Any] | None,
    real_target_binding_count: int,
    repo_root: Path = REPO_ROOT,
) -> dict[str, Any]:
    target_id = (
        str(latest_real_target_binding.get("target_id"))
        if latest_real_target_binding
        else None
    )
    base = {
        "work_item_id": "cap_quick_formal_math_prover_lacks_explicit_lean_t_0aafe64f8d0c",
        "current_real_target_binding_count": real_target_binding_count,
        "latest_real_target_binding": target_id,
        "receipt_ref": LEAN_TARGET_RUNNER_RECEIPT_PATH.as_posix(),
        "claim_boundary": (
            "explicit target-runner status only; not a universal finite theorem, "
            "primitive-divisor existence proof, arbitrary generated-row existence "
            "proof, publication authority, or Erdos #257 solution"
        ),
    }
    receipt = _read_json_if_exists(LEAN_TARGET_RUNNER_RECEIPT_PATH, repo_root=repo_root)
    if not receipt:
        return {
            **base,
            "status": "still_open",
            "note": (
                f"Strike projection now exposes {real_target_binding_count} real "
                "Lean target bindings; proofline/support-affordance runners still "
                "need an explicit target-id entrypoint before PROVER metrics can be "
                "interpreted as math-target progress."
            ),
        }

    receipt_target = str(receipt.get("target_theorem") or "")
    receipt_status = str(receipt.get("status") or "")
    target_matches = bool(target_id) and receipt_target == target_id
    runner_passed = target_matches and receipt_status == "PASS"
    return {
        **base,
        "status": "satisfied_by_explicit_target_runner"
        if runner_passed
        else "stale_or_failing_target_runner_receipt",
        "receipt_status": receipt_status,
        "target_matches_latest": target_matches,
        "target_check_status": receipt.get("target_check_status"),
        "print_axioms_status": receipt.get("print_axioms_status"),
        "axiom_dependency_class": receipt.get("axiom_dependency_class"),
        "axiom_dependencies": receipt.get("axiom_dependencies", []),
        "custom_axiom_dependencies": receipt.get("custom_axiom_dependencies", []),
        "sorry_like_axiom_dependency_detected": receipt.get(
            "sorry_like_axiom_dependency_detected"
        ),
        "audit_mode": receipt.get("audit_mode", "single_target"),
        "target_count": receipt.get("target_count", 1),
        "all_targets_foundational_or_none": receipt.get(
            "all_targets_foundational_or_none"
        ),
        "audited_targets": receipt.get("targets", []),
        "runner_claim_boundary": receipt.get("claim_boundary"),
        "note": (
            "Latest real target has an explicit Lean target-runner receipt with "
            "#check and #print axioms output."
            if runner_passed
            else "Target-runner receipt is absent for the latest target or did not pass."
        ),
    }


def _write_json(path: Path, payload: Mapping[str, Any], *, repo_root: Path = REPO_ROOT) -> None:
    target = _repo_path(path, repo_root=repo_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(
        json.dumps(dict(payload), ensure_ascii=True, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )


def _write_text(path: Path, payload: str, *, repo_root: Path = REPO_ROOT) -> None:
    target = _repo_path(path, repo_root=repo_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(payload, encoding="utf-8")


def _canonical_json(value: Any) -> str:
    return json.dumps(value, ensure_ascii=True, sort_keys=True, separators=(",", ":"))


def _sha256(value: Any) -> str:
    text = value if isinstance(value, str) else _canonical_json(value)
    return "sha256:" + hashlib.sha256(text.encode("utf-8")).hexdigest()


def _int_sha256(value: int) -> str:
    sign = b"-" if value < 0 else b"+"
    magnitude = abs(value)
    byte_count = max(1, (magnitude.bit_length() + 7) // 8)
    return "sha256:" + hashlib.sha256(sign + magnitude.to_bytes(byte_count, "big")).hexdigest()


def _int_digit_count_estimate(value: int) -> int:
    magnitude = abs(value)
    if magnitude == 0:
        return 1
    return int((magnitude.bit_length() - 1) * math.log10(2)) + 1


@lru_cache(maxsize=None)
def _factorint(n: int) -> dict[int, int]:
    if n < 0:
        n = -n
    if n <= 1:
        return {}
    if _sympy_factorint is None:
        raise RuntimeError("sympy.factorint is required for period non-collapse strike factoring")
    return {int(prime): int(exp) for prime, exp in _sympy_factorint(n).items()}


def _factor_json(factors: Mapping[int, int]) -> dict[str, int]:
    return {str(prime): int(exp) for prime, exp in sorted(factors.items())}


def _valuation(n: int, prime: int) -> int:
    if n == 0:
        return 0
    count = 0
    while n % prime == 0:
        n //= prime
        count += 1
    return count


def _order_dividing_period(base: int, modulus: int, period: int, period_factors: Mapping[int, int]) -> int:
    if modulus <= 1:
        return 1
    if math.gcd(base, modulus) != 1:
        raise ValueError(f"base {base} is not invertible modulo {modulus}")
    order = period
    for prime, exponent in sorted(period_factors.items()):
        for _ in range(exponent):
            candidate = order // prime
            if order % prime == 0 and pow(base, candidate, modulus) == 1:
                order = candidate
            else:
                break
    return order


def _divisors(n: int) -> list[int]:
    factors = _factorint(n)
    divisors = [1]
    for prime, exponent in sorted(factors.items()):
        divisors = [d * prime**e for d in divisors for e in range(exponent + 1)]
    return sorted(divisors)


def _prime_power_components(period_factors: Mapping[int, int]) -> list[dict[str, int | str]]:
    rows: list[dict[str, int | str]] = []
    for prime, exponent in sorted(period_factors.items()):
        rows.append(
            {
                "component_id": f"{prime}^{exponent}",
                "prime": prime,
                "exponent": exponent,
                "prime_power": prime**exponent,
            }
        )
    return rows


def _source_n_candidates(subset: Sequence[int], prime: int, exponent: int) -> list[int]:
    return [n for n in subset if _valuation(n, prime) == exponent]


def _component_witnesses(
    *,
    base: int,
    subset: Sequence[int],
    period: int,
    period_factors: Mapping[int, int],
    q_factors: Mapping[int, int],
) -> list[dict[str, Any]]:
    witnesses: list[dict[str, Any]] = []
    for component in _prime_power_components(period_factors):
        prime = int(component["prime"])
        exponent = int(component["exponent"])
        best: dict[str, Any] | None = None
        best_component_exponent = -1
        for q_prime, q_exponent in sorted(q_factors.items()):
            modulus = q_prime**q_exponent
            local_order = _order_dividing_period(base, modulus, period, period_factors)
            component_exponent = _valuation(local_order, prime)
            if component_exponent > best_component_exponent:
                best_component_exponent = component_exponent
                best = {
                    "prime": q_prime,
                    "exponent_in_Q": q_exponent,
                    "witness_modulus_ref": f"{q_prime}^{q_exponent}",
                    "ord_mod_prime_power": local_order,
                    "component_exponent_in_order": component_exponent,
                }
        survived = best_component_exponent >= exponent
        witnesses.append(
            {
                "component_id": component["component_id"],
                "source_n_candidates": _source_n_candidates(subset, prime, exponent),
                "survived": survived,
                "witness_factor": best,
            }
        )
    return witnesses


def _collapse_divisor_checks(
    *,
    base: int,
    subset: Sequence[int],
    period: int,
    period_factors: Mapping[int, int],
    denominator: int,
    order: int,
) -> list[dict[str, Any]]:
    if not period_factors:
        return []
    b_to_l_minus_one = base**period - 1
    a_l = sum(b_to_l_minus_one // (base**n - 1) for n in subset)
    checks: list[dict[str, Any]] = []
    for prime in sorted(period_factors):
        l_over_p = period // prime
        m_p = b_to_l_minus_one // (base**l_over_p - 1)
        residue = a_l % m_p
        collapse_detected = residue == 0
        order_divides_l_over_p = l_over_p % order == 0
        q_divides_smaller_period = denominator == 1 or pow(base, l_over_p, denominator) == 1
        checks.append(
            {
                "prime": prime,
                "L_over_p": l_over_p,
                "M_p_sha256": _int_sha256(m_p),
                "M_p_digit_count_estimate": _int_digit_count_estimate(m_p),
                "A_L_mod_M_p_sha256": _int_sha256(residue),
                "A_L_mod_M_p_digit_count_estimate": _int_digit_count_estimate(residue),
                "residue_is_zero": collapse_detected,
                "collapse_detected": collapse_detected,
                "ord_Q_b_divides_L_over_p": order_divides_l_over_p,
                "Q_divides_b_to_L_over_p_minus_1": q_divides_smaller_period,
                "equivalence_holds": collapse_detected == order_divides_l_over_p == q_divides_smaller_period,
                "certificate": (
                    "nonzero_residue_blocks_period_collapse"
                    if not collapse_detected
                    else "zero_residue_collapse_candidate"
                ),
            }
        )
    return checks


def _is_power_of_two(n: int) -> bool:
    return n > 0 and n & (n - 1) == 0


def _zsigmondy_exception_class(base: int, n0: int) -> str | None:
    if base == 2 and n0 == 6:
        return "zsigmondy_exception_base2_n6"
    if n0 == 2 and _is_power_of_two(base + 1):
        return "zsigmondy_exception_n2_base_plus_one_power_of_two"
    return None


def _divisibility_maximal_elements(values: Sequence[int]) -> list[int]:
    unique_values = sorted(set(int(value) for value in values))
    return [
        value
        for value in unique_values
        if not any(other != value and other % value == 0 for other in unique_values)
    ]


@lru_cache(maxsize=None)
def _primitive_prime_candidates(base: int, n0: int) -> list[dict[str, Any]]:
    n0_factors = _factorint(n0)
    rows: list[dict[str, Any]] = []
    for prime, exponent in sorted(_factorint(base**n0 - 1).items()):
        ord_prime = _order_dividing_period(base, prime, n0, n0_factors)
        rows.append(
            {
                "prime_q": prime,
                "q_factor_exponent_in_b_to_n0_minus_1": exponent,
                "ord_q_b": ord_prime,
                "primitive_prime_for_b_to_n0_minus_1": ord_prime == n0,
            }
        )
    return rows


def _valuation_witness_key(row: Mapping[str, Any]) -> tuple[int, int, int, int]:
    return (
        int(row["valuation_deficit"]),
        1 if row["primitive_prime_for_b_to_n0_minus_1"] else 0,
        int(row["v_q_M_p"]),
        int(row["prime_q"]),
    )


def _valuation_witness_checks(
    *,
    base: int,
    subset: Sequence[int],
    period: int,
    period_factors: Mapping[int, int],
    collapse_checks: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    if not period_factors:
        return []
    b_to_l_minus_one = base**period - 1
    a_l = sum(b_to_l_minus_one // (base**n - 1) for n in subset)
    collapse_by_prime = {int(row["prime"]): row for row in collapse_checks}
    checks: list[dict[str, Any]] = []
    for prime in sorted(period_factors):
        l_over_p = period // prime
        m_p = b_to_l_minus_one // (base**l_over_p - 1)
        p_exponent_in_l = _valuation(period, prime)
        active_n = [n for n in subset if _valuation(n, prime) == p_exponent_in_l]
        maximal_active_n = _divisibility_maximal_elements(active_n)
        best_primitive: dict[str, Any] | None = None
        best_exception: dict[str, Any] | None = None
        best_auxiliary: dict[str, Any] | None = None
        primitive_candidate_count = 0
        successful_candidate_count = 0
        for n0 in maximal_active_n:
            exception_class = _zsigmondy_exception_class(base, n0)
            for candidate in _primitive_prime_candidates(base, n0):
                q = int(candidate["prime_q"])
                v_q_m_p = _valuation(m_p, q)
                v_q_a_l = _valuation(a_l, q)
                valuation_deficit = v_q_m_p - v_q_a_l
                is_primitive = bool(candidate["primitive_prime_for_b_to_n0_minus_1"])
                if is_primitive:
                    primitive_candidate_count += 1
                witness = {
                    **candidate,
                    "candidate_n0": n0,
                    "exception_class": exception_class,
                    "q_divides_L_over_n0": (period // n0) % q == 0,
                    "v_q_M_p": v_q_m_p,
                    "v_q_A_L": v_q_a_l,
                    "valuation_deficit": valuation_deficit,
                }
                if valuation_deficit <= 0:
                    continue
                successful_candidate_count += 1
                if is_primitive and (
                    best_primitive is None or _valuation_witness_key(witness) > _valuation_witness_key(best_primitive)
                ):
                    best_primitive = witness
                if exception_class and (
                    best_exception is None or _valuation_witness_key(witness) > _valuation_witness_key(best_exception)
                ):
                    best_exception = witness
                if best_auxiliary is None or _valuation_witness_key(witness) > _valuation_witness_key(best_auxiliary):
                    best_auxiliary = witness
        collapse_check = collapse_by_prime[prime]
        if collapse_check["collapse_detected"] or not collapse_check["equivalence_holds"]:
            witness_status = "counterexample_or_bug"
            selected_witness = best_auxiliary
        elif best_primitive is not None:
            witness_status = "primitive_maximal_active_witness"
            selected_witness = best_primitive
        elif best_exception is not None:
            witness_status = "zsigmondy_exception_handled"
            selected_witness = best_exception
        elif best_auxiliary is not None:
            witness_status = "auxiliary_valuation_witness"
            selected_witness = best_auxiliary
        else:
            witness_status = "unexplained_noncollapse"
            selected_witness = None
        checks.append(
            {
                "prime": prime,
                "L_over_p": l_over_p,
                "v_p_L": p_exponent_in_l,
                "active_n_with_full_p_adic_valuation": active_n,
                "divisibility_maximal_active_n": maximal_active_n,
                "multi_maximal_antichain": len(maximal_active_n) > 1,
                "primitive_candidate_count": primitive_candidate_count,
                "successful_candidate_count": successful_candidate_count,
                "witness_status": witness_status,
                "selected_witness": selected_witness,
                "collapse_detected": bool(collapse_check["collapse_detected"]),
                "equivalence_holds": bool(collapse_check["equivalence_holds"]),
                "certificate": (
                    "q_adic_valuation_deficit_blocks_M_p_divisibility"
                    if selected_witness is not None
                    else "no_local_valuation_witness_found"
                ),
            }
        )
    return checks


def _case_exception_flags(
    base: int,
    subset: Sequence[int],
    period: int,
    component_witnesses: Sequence[Mapping[str, Any]],
    collapse_checks: Sequence[Mapping[str, Any]],
    valuation_checks: Sequence[Mapping[str, Any]],
) -> list[str]:
    flags: list[str] = []
    if period == 1:
        flags.append("lcm_one_trivial")
    if any(base**n - 1 == 1 for n in subset):
        flags.append("unit_denominator_term_present")
    if base == 2 and 6 in subset:
        flags.append("zsigmondy_bang_exception_index_6_present")
    if any(not witness.get("survived") for witness in component_witnesses):
        flags.append("missing_prime_power_component_witness")
    if any(check.get("collapse_detected") for check in collapse_checks):
        flags.append("collapse_divisor_detected")
    if any(not check.get("equivalence_holds") for check in collapse_checks):
        flags.append("collapse_divisor_equivalence_mismatch")
    if any(check.get("witness_status") == "zsigmondy_exception_handled" for check in valuation_checks):
        flags.append("zsigmondy_exception_handled_by_valuation_witness")
    if any(check.get("witness_status") == "unexplained_noncollapse" for check in valuation_checks):
        flags.append("valuation_witness_unexplained")
    if any(check.get("witness_status") == "counterexample_or_bug" for check in valuation_checks):
        flags.append("valuation_witness_counterexample_or_bug")
    return flags


def _build_case(base: int, subset: Sequence[int]) -> dict[str, Any]:
    return _build_case_cached(base, tuple(int(n) for n in subset))


@lru_cache(maxsize=None)
def _build_case_cached(base: int, subset_tuple: tuple[int, ...]) -> dict[str, Any]:
    value = sum((Fraction(1, base**n - 1) for n in subset_tuple), Fraction(0, 1))
    denominator = value.denominator
    period = math.lcm(*subset_tuple)
    period_factors = _factorint(period)
    q_factors = _factorint(denominator)
    order = _order_dividing_period(base, denominator, period, period_factors)
    witnesses = _component_witnesses(
        base=base,
        subset=subset_tuple,
        period=period,
        period_factors=period_factors,
        q_factors=q_factors,
    )
    lost_factors = [row["component_id"] for row in witnesses if not row["survived"]]
    collapse_checks = _collapse_divisor_checks(
        base=base,
        subset=subset_tuple,
        period=period,
        period_factors=period_factors,
        denominator=denominator,
        order=order,
    )
    valuation_checks = _valuation_witness_checks(
        base=base,
        subset=subset_tuple,
        period=period,
        period_factors=period_factors,
        collapse_checks=collapse_checks,
    )
    collapse_failures = [f"p={row['prime']}" for row in collapse_checks if row["collapse_detected"]]
    collapse_equivalence_failures = [f"p={row['prime']}" for row in collapse_checks if not row["equivalence_holds"]]
    valuation_failures = [
        f"p={row['prime']}:{row['witness_status']}"
        for row in valuation_checks
        if row["witness_status"] in {"unexplained_noncollapse", "counterexample_or_bug"}
    ]
    pass_fail = "pass"
    if order != period or lost_factors or collapse_failures or collapse_equivalence_failures:
        pass_fail = "fail"
    case_id = f"b{base}_F{'-'.join(str(n) for n in subset_tuple)}"
    return {
        "case_id": case_id,
        "b": base,
        "F": list(subset_tuple),
        "Q": denominator,
        "L": period,
        "ord_Q_b": order,
        "pass_fail": pass_fail,
        "prime_factorization_Q": _factor_json(q_factors),
        "prime_power_components_of_L": _prime_power_components(period_factors),
        "witness_for_each_component": witnesses,
        "collapse_divisor_checks": collapse_checks,
        "valuation_witness_checks": valuation_checks,
        "cyclotomic_factor_sources": "summarized_by_prime_power_components_of_L_and_witness_source_n_candidates",
        "lost_factors": lost_factors,
        "collapse_divisor_failures": collapse_failures,
        "collapse_divisor_equivalence_failures": collapse_equivalence_failures,
        "valuation_witness_failures": valuation_failures,
        "exception_flags": _case_exception_flags(base, subset_tuple, period, witnesses, collapse_checks, valuation_checks),
        "minimal_failure_if_any": None if pass_fail == "pass" else case_id,
    }


def _compact_case(row: Mapping[str, Any]) -> dict[str, Any]:
    factorization = row["prime_factorization_Q"]
    witnesses = row["witness_for_each_component"]
    collapse_checks = row["collapse_divisor_checks"]
    valuation_checks = row["valuation_witness_checks"]
    valuation_status_counts = Counter(check["witness_status"] for check in valuation_checks)
    valuation_exception_counts = Counter(
        check["selected_witness"]["exception_class"]
        for check in valuation_checks
        if check["selected_witness"] and check["selected_witness"].get("exception_class")
    )
    return {
        "case_id": row["case_id"],
        "b": row["b"],
        "F": row["F"],
        "L": row["L"],
        "Q_sha256": _sha256(str(row["Q"])),
        "Q_digit_count": len(str(row["Q"])),
        "ord_Q_b": row["ord_Q_b"],
        "pass_fail": row["pass_fail"],
        "prime_factorization_Q_sha256": _sha256(factorization),
        "prime_factor_count": len(factorization),
        "witness_for_each_component_sha256": _sha256(witnesses),
        "component_count": len(witnesses),
        "survived_component_count": sum(1 for witness in witnesses if witness["survived"]),
        "collapse_divisor_prime_check_count": len(collapse_checks),
        "collapse_divisor_collapse_count": sum(1 for check in collapse_checks if check["collapse_detected"]),
        "collapse_divisor_equivalence_mismatch_count": sum(
            1 for check in collapse_checks if not check["equivalence_holds"]
        ),
        "collapse_divisor_checks_sha256": _sha256(collapse_checks),
        "valuation_witness_prime_check_count": len(valuation_checks),
        "valuation_witness_status_counts": dict(sorted(valuation_status_counts.items())),
        "valuation_witness_exception_class_counts": dict(sorted(valuation_exception_counts.items())),
        "valuation_witness_primitive_count": valuation_status_counts.get("primitive_maximal_active_witness", 0),
        "valuation_witness_exception_count": valuation_status_counts.get("zsigmondy_exception_handled", 0),
        "valuation_witness_auxiliary_count": valuation_status_counts.get("auxiliary_valuation_witness", 0),
        "valuation_witness_unexplained_count": valuation_status_counts.get("unexplained_noncollapse", 0),
        "valuation_witness_counterexample_or_bug_count": valuation_status_counts.get("counterexample_or_bug", 0),
        "valuation_witness_multi_maximal_antichain_count": sum(
            1 for check in valuation_checks if check["multi_maximal_antichain"]
        ),
        "valuation_witness_checks_sha256": _sha256(valuation_checks),
        "cyclotomic_factor_sources": "digest_backed_by_detailed_sample_or_recompute_builder",
        "lost_factors": row["lost_factors"],
        "collapse_divisor_failures": row["collapse_divisor_failures"],
        "collapse_divisor_equivalence_failures": row["collapse_divisor_equivalence_failures"],
        "valuation_witness_failures": row["valuation_witness_failures"],
        "exception_flags": row["exception_flags"],
        "minimal_failure_if_any": row["minimal_failure_if_any"],
    }


def _sample_valuation_witness(row: Mapping[str, Any], check: Mapping[str, Any], sample_kind: str) -> dict[str, Any]:
    return {
        "sample_kind": sample_kind,
        "case_id": row["case_id"],
        "b": row["b"],
        "F": row["F"],
        "L": row["L"],
        "prime": check["prime"],
        "L_over_p": check["L_over_p"],
        "active_n_with_full_p_adic_valuation": check["active_n_with_full_p_adic_valuation"],
        "divisibility_maximal_active_n": check["divisibility_maximal_active_n"],
        "multi_maximal_antichain": check["multi_maximal_antichain"],
        "witness_status": check["witness_status"],
        "selected_witness": check["selected_witness"],
        "certificate": check["certificate"],
    }


def _maybe_add_valuation_samples(
    samples: dict[str, dict[str, Any]],
    row: Mapping[str, Any],
) -> None:
    for check in row["valuation_witness_checks"]:
        status = str(check["witness_status"])
        if status == "primitive_maximal_active_witness":
            samples.setdefault("primitive_maximal_active_witness", _sample_valuation_witness(row, check, status))
        if status == "zsigmondy_exception_handled":
            samples.setdefault("zsigmondy_exception_handled", _sample_valuation_witness(row, check, status))
        if check["multi_maximal_antichain"]:
            samples.setdefault("multi_maximal_antichain", _sample_valuation_witness(row, check, "multi_maximal_antichain"))
        if status == "unexplained_noncollapse":
            samples.setdefault("unexplained_noncollapse", _sample_valuation_witness(row, check, status))
        if status == "counterexample_or_bug":
            samples.setdefault("counterexample_or_bug", _sample_valuation_witness(row, check, status))


def _valuation_witness_summary(case_rows: Sequence[Mapping[str, Any]]) -> dict[str, Any]:
    status_counts: Counter[str] = Counter()
    exception_counts: Counter[str] = Counter()
    for row in case_rows:
        status_counts.update(row["valuation_witness_status_counts"])
        exception_counts.update(row["valuation_witness_exception_class_counts"])
    unexplained_count = status_counts.get("unexplained_noncollapse", 0)
    counterexample_or_bug_count = status_counts.get("counterexample_or_bug", 0)
    return {
        "route_id": "valuation_witness_route",
        "route_status": "PASS" if unexplained_count == 0 and counterexample_or_bug_count == 0 else "GAP",
        "checked_case_count": len(case_rows),
        "prime_component_check_count": sum(row["valuation_witness_prime_check_count"] for row in case_rows),
        "primitive_maximal_active_witness_count": status_counts.get("primitive_maximal_active_witness", 0),
        "zsigmondy_exception_count": status_counts.get("zsigmondy_exception_handled", 0),
        "auxiliary_valuation_witness_count": status_counts.get("auxiliary_valuation_witness", 0),
        "multi_maximal_antichain_count": sum(row["valuation_witness_multi_maximal_antichain_count"] for row in case_rows),
        "unexplained_noncollapse_count": unexplained_count,
        "counterexample_or_bug_count": counterexample_or_bug_count,
        "status_counts": dict(sorted(status_counts.items())),
        "exception_class_counts": dict(sorted(exception_counts.items())),
        "current_candidate_theorem": "primitive_maximal_active_witness_blocks_collapse_with_explicit_zsigmondy_exceptions",
        "claim_boundary": "bounded valuation-witness route evidence, not a proof of the finite theorem or Erdos #257",
    }


def _new_fragility_accumulator() -> dict[str, Any]:
    return {
        "checked_case_count": 0,
        "prime_component_check_count": 0,
        "assertion_count": 0,
        "failure_count": 0,
        "check_counts": Counter(),
        "failure_check_counts": Counter(),
        "targeted_edge_case_ids": set(),
        "failure_samples": [],
    }


def _record_fragility_check(
    accumulator: dict[str, Any],
    *,
    check_id: str,
    ok: bool,
    case_id: str,
    detail: Mapping[str, Any] | None = None,
) -> None:
    accumulator["assertion_count"] += 1
    accumulator["check_counts"][check_id] += 1
    if ok:
        return
    accumulator["failure_count"] += 1
    accumulator["failure_check_counts"][check_id] += 1
    if len(accumulator["failure_samples"]) < 12:
        accumulator["failure_samples"].append(
            {
                "case_id": case_id,
                "check_id": check_id,
                "detail": dict(detail or {}),
            }
        )


def _b_and_a_l(base: int, subset: Sequence[int], period: int) -> tuple[int, int]:
    b_to_l_minus_one = base**period - 1
    a_l = sum(b_to_l_minus_one // (base**n - 1) for n in subset)
    return b_to_l_minus_one, a_l


def _m_p(base: int, period: int, prime: int) -> int:
    return (base**period - 1) // (base ** (period // prime) - 1)


def _summand_valuations(base: int, subset: Sequence[int], period: int, prime_q: int) -> dict[int, int]:
    b_to_l_minus_one = base**period - 1
    return {
        n: _valuation(b_to_l_minus_one // (base**n - 1), prime_q)
        for n in subset
    }


def _summand_terms(base: int, subset: Sequence[int], period: int) -> dict[int, int]:
    b_to_l_minus_one = base**period - 1
    return {n: b_to_l_minus_one // (base**n - 1) for n in subset}


def _local_layer_certificate_from_witness(
    *,
    base: int,
    subset: Sequence[int],
    period: int,
    prime: int,
    witness: Mapping[str, Any],
    witness_source: str,
    repair_class: str,
    selection_rank: int,
) -> dict[str, Any]:
    q = int(witness["prime_q"])
    b_to_l_minus_one, a_l = _b_and_a_l(base, subset, period)
    m_p = _m_p(base, period, prime)
    terms = _summand_terms(base, subset, period)
    term_valuations = {n: _valuation(term, q) for n, term in terms.items()}
    minimal_valuation = min(term_valuations.values())
    minimal_layer = sorted(n for n, value in term_valuations.items() if value == minimal_valuation)
    q_power = q**minimal_valuation
    normalized_terms = [
        {
            "n": n,
            "term_mod_q_after_dividing_q_power": (terms[n] // q_power) % q,
        }
        for n in minimal_layer
    ]
    minimal_layer_residue_mod_q = sum(row["term_mod_q_after_dividing_q_power"] for row in normalized_terms) % q
    residue_nonzero = minimal_layer_residue_mod_q != 0
    v_q_a_l_actual = _valuation(a_l, q)
    v_q_a_l_certified = minimal_valuation if residue_nonzero else v_q_a_l_actual
    v_q_m_p = _valuation(m_p, q)
    valuation_deficit = v_q_m_p - v_q_a_l_certified
    certificate_status = (
        "local_layer_certificate_pass"
        if residue_nonzero and valuation_deficit > 0
        else "residue_zero_unresolved"
    )
    n0 = int(witness.get("candidate_n0", 0))
    prior_unique_minimal_failed = not (
        minimal_layer == [n0]
        and v_q_a_l_actual == minimal_valuation
        and v_q_a_l_actual == int(witness.get("v_q_A_L", v_q_a_l_actual))
    )
    return {
        "case_id": None,
        "b": base,
        "F": list(subset),
        "L": period,
        "p": prime,
        "q": q,
        "M_p_sha256": _int_sha256(m_p),
        "M_p_digit_count_estimate": _int_digit_count_estimate(m_p),
        "A_L_sha256": _int_sha256(a_l),
        "A_L_digit_count_estimate": _int_digit_count_estimate(a_l),
        "selected_witness_kind": str(witness.get("exception_class") or witness.get("witness_status") or "valuation_witness"),
        "selected_witness": dict(witness),
        "witness_source": witness_source,
        "selection_rank": selection_rank,
        "minimal_layer": minimal_layer,
        "minimal_valuation": minimal_valuation,
        "minimal_layer_residue_mod_q": minimal_layer_residue_mod_q,
        "normalized_minimal_layer_terms_mod_q": normalized_terms,
        "residue_nonzero": residue_nonzero,
        "v_q_M_p": v_q_m_p,
        "v_q_A_L_actual": v_q_a_l_actual,
        "v_q_A_L_or_certified_value": v_q_a_l_certified,
        "valuation_deficit": valuation_deficit,
        "certificate_status": certificate_status,
        "repair_class": repair_class if certificate_status == "local_layer_certificate_pass" else "residue_zero_unresolved",
        "prior_unique_minimal_failed": prior_unique_minimal_failed,
        "claim_boundary": "local q-adic layer certificate for one bounded prime-component row, not a proof of the universal theorem",
    }


def _local_layer_candidate_witnesses(
    *,
    base: int,
    subset: Sequence[int],
    period: int,
    prime: int,
) -> list[dict[str, Any]]:
    p_exponent_in_l = _valuation(period, prime)
    active_n = [n for n in subset if _valuation(n, prime) == p_exponent_in_l]
    maximal_active_n = _divisibility_maximal_elements(active_n)
    m_p = _m_p(base, period, prime)
    _, a_l = _b_and_a_l(base, subset, period)
    candidates: list[dict[str, Any]] = []
    seen: set[tuple[int, int, str]] = set()
    for n0 in maximal_active_n:
        exception_class = _zsigmondy_exception_class(base, n0)
        for candidate in _primitive_prime_candidates(base, n0):
            q = int(candidate["prime_q"])
            witness = {
                **candidate,
                "candidate_n0": n0,
                "exception_class": exception_class,
                "q_divides_L_over_n0": (period // n0) % q == 0,
                "v_q_M_p": _valuation(m_p, q),
                "v_q_A_L": _valuation(a_l, q),
                "valuation_deficit": _valuation(m_p, q) - _valuation(a_l, q),
                "selection_hint": "candidate_reselection",
            }
            key = (int(witness["prime_q"]), int(witness["candidate_n0"]), str(witness["selection_hint"]))
            if key not in seen:
                seen.add(key)
                candidates.append(witness)
        if base == 2 and n0 == 6 and prime in {2, 3}:
            q = 3
            witness = {
                "prime_q": q,
                "q_factor_exponent_in_b_to_n0_minus_1": _valuation(base**n0 - 1, q),
                "ord_q_b": _order_dividing_period(base, q, n0, _factorint(n0)),
                "primitive_prime_for_b_to_n0_minus_1": False,
                "candidate_n0": n0,
                "exception_class": "zsigmondy_exception_base2_n6",
                "q_divides_L_over_n0": (period // n0) % q == 0,
                "v_q_M_p": _valuation(m_p, q),
                "v_q_A_L": _valuation(a_l, q),
                "valuation_deficit": _valuation(m_p, q) - _valuation(a_l, q),
                "selection_hint": "exception_specific_q3",
            }
            key = (int(witness["prime_q"]), int(witness["candidate_n0"]), str(witness["selection_hint"]))
            if key not in seen:
                seen.add(key)
                candidates.append(witness)
    return candidates


def _compact_local_layer_certificate(certificate: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "case_id": certificate["case_id"],
        "b": certificate["b"],
        "F": certificate["F"],
        "L": certificate["L"],
        "p": certificate["p"],
        "q": certificate["q"],
        "candidate_n0": certificate["selected_witness"].get("candidate_n0"),
        "minimal_layer": certificate["minimal_layer"],
        "minimal_valuation": certificate["minimal_valuation"],
        "minimal_layer_residue_mod_q": certificate["minimal_layer_residue_mod_q"],
        "residue_nonzero": certificate["residue_nonzero"],
        "v_q_M_p": certificate["v_q_M_p"],
        "v_q_A_L_or_certified_value": certificate["v_q_A_L_or_certified_value"],
        "valuation_deficit": certificate["valuation_deficit"],
        "certificate_status": certificate["certificate_status"],
        "repair_class": certificate["repair_class"],
        "witness_source": certificate["witness_source"],
        "prior_unique_minimal_failed": certificate["prior_unique_minimal_failed"],
        "M_p_sha256": certificate["M_p_sha256"],
        "A_L_sha256": certificate["A_L_sha256"],
    }


def _mod_inverse(value: int, modulus: int) -> int:
    return pow(value % modulus, -1, modulus)


def _residue_formula_applicability_class(certificate: Mapping[str, Any]) -> str:
    q = int(certificate["q"])
    exception_class = certificate["selected_witness"].get("exception_class")
    if q == 2:
        return "q2_exception_formula"
    if exception_class == "zsigmondy_exception_base2_n6":
        return "zsigmondy_2_6_formula"
    return "odd_prime_order_formula"


def _residue_formula_from_certificate(certificate: Mapping[str, Any]) -> dict[str, Any]:
    q = int(certificate["q"])
    witness = certificate["selected_witness"]
    applicability_class = _residue_formula_applicability_class(certificate)
    formula_base = {
        "case_id": certificate["case_id"],
        "b": certificate["b"],
        "F": list(certificate["F"]),
        "L": certificate["L"],
        "p": certificate["p"],
        "q": q,
        "d": witness.get("ord_q_b"),
        "candidate_n0": witness.get("candidate_n0"),
        "exception_class": witness.get("exception_class"),
        "repair_class": certificate["repair_class"],
        "applicability_class": applicability_class,
        "certificate_minimal_layer": certificate["minimal_layer"],
        "certificate_residue_mod_q": certificate["minimal_layer_residue_mod_q"],
    }
    if q == 2:
        formula_residue = certificate["minimal_layer_residue_mod_q"]
        return {
            **formula_base,
            "formula_status": "formula_match",
            "formula_basis": "direct_q2_exception_local_layer_certificate",
            "R": None,
            "r": None,
            "U_L_mod_q": None,
            "minimal_layer_formula": list(certificate["minimal_layer"]),
            "normalized_quotient_terms_mod_q": [],
            "formula_residue_mod_q": formula_residue,
            "formula_matches_certificate": True,
            "formula_residue_nonzero": bool(formula_residue),
            "unavailable_reason": None,
        }

    d = int(witness.get("ord_q_b") or 0)
    period = int(certificate["L"])
    subset = tuple(int(n) for n in certificate["F"])
    if d <= 0 or period % d != 0:
        return {
            **formula_base,
            "formula_status": "residue_formula_unavailable",
            "formula_basis": "odd_prime_order_quotient_formula",
            "R": None,
            "r": None,
            "U_L_mod_q": None,
            "minimal_layer_formula": [],
            "normalized_quotient_terms_mod_q": [],
            "formula_residue_mod_q": None,
            "formula_matches_certificate": False,
            "formula_residue_nonzero": False,
            "unavailable_reason": "ord_q_b_does_not_divide_L",
        }

    divisible_terms = [n for n in subset if n % d == 0]
    if not divisible_terms:
        return {
            **formula_base,
            "formula_status": "residue_formula_unavailable",
            "formula_basis": "odd_prime_order_quotient_formula",
            "R": None,
            "r": None,
            "U_L_mod_q": None,
            "minimal_layer_formula": [],
            "normalized_quotient_terms_mod_q": [],
            "formula_residue_mod_q": None,
            "formula_matches_certificate": False,
            "formula_residue_nonzero": False,
            "unavailable_reason": "no_F_term_divisible_by_ord_q_b",
        }

    quotient_valuations = {n: _valuation(n // d, q) for n in divisible_terms}
    r = max(quotient_valuations.values())
    R = _valuation(period // d, q)
    u_l = (period // d) // (q**R)
    minimal_layer_formula = sorted(n for n, value in quotient_valuations.items() if value == r)
    quotient_terms = []
    formula_residue = 0
    for n in minimal_layer_formula:
        u_n = (n // d) // (q**r)
        term_mod_q = (u_l * _mod_inverse(u_n, q)) % q
        formula_residue = (formula_residue + term_mod_q) % q
        quotient_terms.append(
            {
                "n": n,
                "U_n_mod_q": u_n % q,
                "term_mod_q": term_mod_q,
            }
        )
    formula_matches_certificate = (
        minimal_layer_formula == list(certificate["minimal_layer"])
        and formula_residue == certificate["minimal_layer_residue_mod_q"]
    )
    formula_residue_nonzero = formula_residue != 0
    if not formula_matches_certificate:
        formula_status = "formula_mismatch"
    elif not formula_residue_nonzero:
        formula_status = "formula_residue_zero"
    else:
        formula_status = "formula_match"
    return {
        **formula_base,
        "formula_status": formula_status,
        "formula_basis": "odd_prime_order_quotient_formula",
        "R": R,
        "r": r,
        "U_L_mod_q": u_l % q,
        "minimal_layer_formula": minimal_layer_formula,
        "normalized_quotient_terms_mod_q": quotient_terms,
        "formula_residue_mod_q": formula_residue,
        "formula_matches_certificate": formula_matches_certificate,
        "formula_residue_nonzero": formula_residue_nonzero,
        "unavailable_reason": None,
    }


def _compact_residue_formula_row(formula: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "case_id": formula["case_id"],
        "b": formula["b"],
        "F": formula["F"],
        "L": formula["L"],
        "p": formula["p"],
        "q": formula["q"],
        "d": formula["d"],
        "candidate_n0": formula["candidate_n0"],
        "applicability_class": formula["applicability_class"],
        "repair_class": formula["repair_class"],
        "minimal_layer_formula": formula["minimal_layer_formula"],
        "formula_residue_mod_q": formula["formula_residue_mod_q"],
        "certificate_residue_mod_q": formula["certificate_residue_mod_q"],
        "formula_matches_certificate": formula["formula_matches_certificate"],
        "formula_residue_nonzero": formula["formula_residue_nonzero"],
        "formula_status": formula["formula_status"],
    }


def _sample_key_for_residue_formula(formula: Mapping[str, Any]) -> str | None:
    applicability_class = str(formula["applicability_class"])
    repair_class = str(formula["repair_class"])
    if applicability_class == "odd_prime_order_formula" and repair_class == "unique_minimal_certificate":
        return "odd_prime_order_singleton_formula"
    if applicability_class == "q2_exception_formula":
        return "q2_exception_formula"
    if applicability_class == "zsigmondy_2_6_formula" and repair_class == "unique_minimal_certificate":
        return "zsigmondy_2_6_singleton_formula"
    if applicability_class == "zsigmondy_2_6_formula" and repair_class == "multi_minimal_residue_nonzero_certificate":
        return "zsigmondy_2_6_multi_minimal_formula"
    if formula["formula_status"] == "formula_mismatch":
        return "formula_mismatch"
    if formula["formula_status"] == "formula_residue_zero":
        return "formula_residue_zero"
    if formula["formula_status"] == "residue_formula_unavailable":
        return "residue_formula_unavailable"
    return None


def _residue_proof_shape_key(formula: Mapping[str, Any]) -> tuple[str, str, int]:
    return (
        str(formula["applicability_class"]),
        str(formula["repair_class"]),
        len(formula["minimal_layer_formula"]),
    )


def _residue_numeric_shape_key(formula: Mapping[str, Any]) -> tuple[Any, ...]:
    return (
        str(formula["applicability_class"]),
        formula["q"],
        formula["d"],
        len(formula["minimal_layer_formula"]),
        tuple(row["term_mod_q"] for row in formula["normalized_quotient_terms_mod_q"]),
        str(formula["repair_class"]),
    )


def _shape_id(prefix: str, key: Any) -> str:
    digest = hashlib.sha256(_canonical_json(key).encode("utf-8")).hexdigest()[:12]
    return f"{prefix}_{digest}"


def _new_residue_formula_accumulator() -> dict[str, Any]:
    return {
        "checked_case_count": 0,
        "formula_check_count": 0,
        "formula_match_count": 0,
        "formula_mismatch_count": 0,
        "formula_residue_zero_count": 0,
        "formula_unavailable_count": 0,
        "applicability_class_counts": Counter(),
        "repair_class_counts": Counter(),
        "formula_status_counts": Counter(),
        "formula_digest_rows": [],
        "proof_shapes": {},
        "numeric_shapes": {},
        "sample_formulas": {},
        "mismatch_samples": [],
        "zero_samples": [],
        "unavailable_samples": [],
    }


def _accumulate_shape_row(shape_rows: dict[Any, dict[str, Any]], key: Any, formula: Mapping[str, Any]) -> None:
    row = shape_rows.setdefault(
        key,
        {
            "row_count": 0,
            "formula_mismatch_count": 0,
            "formula_zero_count": 0,
            "sample_case_ids": [],
        },
    )
    row["row_count"] += 1
    if not formula["formula_matches_certificate"]:
        row["formula_mismatch_count"] += 1
    if not formula["formula_residue_nonzero"]:
        row["formula_zero_count"] += 1
    if len(row["sample_case_ids"]) < 8:
        row["sample_case_ids"].append(formula["case_id"])


def _accumulate_residue_formula(accumulator: dict[str, Any], certificate: Mapping[str, Any]) -> None:
    formula = _residue_formula_from_certificate(certificate)
    compact_formula = _compact_residue_formula_row(formula)
    accumulator["formula_check_count"] += 1
    accumulator["applicability_class_counts"][formula["applicability_class"]] += 1
    accumulator["repair_class_counts"][formula["repair_class"]] += 1
    accumulator["formula_status_counts"][formula["formula_status"]] += 1
    accumulator["formula_digest_rows"].append(compact_formula)
    if formula["formula_matches_certificate"]:
        accumulator["formula_match_count"] += 1
    else:
        accumulator["formula_mismatch_count"] += 1
        if len(accumulator["mismatch_samples"]) < 12:
            accumulator["mismatch_samples"].append(formula)
    if not formula["formula_residue_nonzero"]:
        accumulator["formula_residue_zero_count"] += 1
        if len(accumulator["zero_samples"]) < 12:
            accumulator["zero_samples"].append(formula)
    if formula["formula_status"] == "residue_formula_unavailable":
        accumulator["formula_unavailable_count"] += 1
        if len(accumulator["unavailable_samples"]) < 12:
            accumulator["unavailable_samples"].append(formula)
    sample_key = _sample_key_for_residue_formula(formula)
    if sample_key:
        accumulator["sample_formulas"].setdefault(sample_key, formula)
    _accumulate_shape_row(accumulator["proof_shapes"], _residue_proof_shape_key(formula), formula)
    _accumulate_shape_row(accumulator["numeric_shapes"], _residue_numeric_shape_key(formula), formula)


def _proof_shape_row(key: tuple[str, str, int], row: Mapping[str, Any]) -> dict[str, Any]:
    applicability_class, repair_class, minimal_layer_size = key
    if applicability_class == "q2_exception_formula":
        proof_obligation = "q=2 Zsigmondy n0=2 exception rows stay on explicit local-layer certificates."
    elif repair_class == "multi_minimal_residue_nonzero_certificate":
        proof_obligation = "Prove the zsigmondy n0=6 multi-minimal quotient sum is nonzero for the allowed shapes."
    elif applicability_class == "zsigmondy_2_6_formula":
        proof_obligation = "Prove the zsigmondy n0=6 singleton quotient formula gives a nonzero unit."
    else:
        proof_obligation = "Prove the odd-prime order quotient formula; singleton minimal layer is automatically nonzero."
    return {
        "residue_shape_id": _shape_id("rs", key),
        "applicability_class": applicability_class,
        "repair_class": repair_class,
        "minimal_layer_size": minimal_layer_size,
        "normalized_quotient_pattern_summary": (
            "singleton_unit" if minimal_layer_size == 1 else "multi_minimal_quotient_sum"
        ),
        "row_count": int(row["row_count"]),
        "sample_case_ids": list(row["sample_case_ids"]),
        "formula_mismatch_count": int(row["formula_mismatch_count"]),
        "formula_zero_count": int(row["formula_zero_count"]),
        "proof_obligation": proof_obligation,
    }


def _numeric_shape_row(key: tuple[Any, ...], row: Mapping[str, Any]) -> dict[str, Any]:
    applicability_class, q, d, minimal_layer_size, normalized_pattern, repair_class = key
    return {
        "residue_shape_id": _shape_id("nrs", key),
        "applicability_class": applicability_class,
        "q": q,
        "d": d,
        "minimal_layer_size": minimal_layer_size,
        "normalized_quotient_pattern": list(normalized_pattern),
        "repair_class": repair_class,
        "row_count": int(row["row_count"]),
        "sample_case_ids": list(row["sample_case_ids"]),
        "formula_mismatch_count": int(row["formula_mismatch_count"]),
        "formula_zero_count": int(row["formula_zero_count"]),
    }


def _finalize_residue_formula_kernel(accumulator: Mapping[str, Any]) -> dict[str, Any]:
    proof_shape_rows = [
        _proof_shape_row(key, row)
        for key, row in sorted(
            accumulator["proof_shapes"].items(),
            key=lambda item: (item[0][0], item[0][1], item[0][2]),
        )
    ]
    numeric_shape_rows = [
        _numeric_shape_row(key, row)
        for key, row in sorted(
            accumulator["numeric_shapes"].items(),
            key=lambda item: (-item[1]["row_count"], item[0]),
        )
    ]
    formula_mismatch_count = int(accumulator["formula_mismatch_count"])
    formula_residue_zero_count = int(accumulator["formula_residue_zero_count"])
    formula_unavailable_count = int(accumulator["formula_unavailable_count"])
    route_is_clean = (
        formula_mismatch_count == 0
        and formula_residue_zero_count == 0
        and formula_unavailable_count == 0
    )
    if formula_mismatch_count:
        proof_kernel_route_status = "proof_kernel_split_blocked_by_residue_formula_mismatch"
        current_decisive_blocker = "Inspect formula mismatch rows; the local-layer compiler or quotient formula is incomplete."
    elif formula_residue_zero_count:
        proof_kernel_route_status = "proof_kernel_split_blocked_by_residue_zero_shape"
        current_decisive_blocker = "Inspect formula-zero shapes before Lean or provider review."
    elif formula_unavailable_count:
        proof_kernel_route_status = "proof_kernel_split_blocked_by_residue_formula_unavailable"
        current_decisive_blocker = "Split unavailable residue-formula rows into explicit exception formulas."
    else:
        proof_kernel_route_status = "proof_kernel_split_lifted_to_residue_formula_pending_lean"
        current_decisive_blocker = "Connect odd_prime_order_residue_formula to residue_formula_certificate_blocks_collapse."
    sample_numeric_shapes = numeric_shape_rows[:8]
    seen_numeric_shape_ids = {row["residue_shape_id"] for row in sample_numeric_shapes}
    for row in numeric_shape_rows:
        if row["repair_class"] != "multi_minimal_residue_nonzero_certificate":
            continue
        if row["residue_shape_id"] in seen_numeric_shape_ids:
            continue
        sample_numeric_shapes.append(row)
        seen_numeric_shape_ids.add(row["residue_shape_id"])
    return {
        "route_id": "period_noncollapse_residue_formula_kernel",
        "route_status": "PASS" if route_is_clean else "GAP",
        "proof_kernel_route_status": proof_kernel_route_status,
        "formula_check_count": int(accumulator["formula_check_count"]),
        "formula_match_count": int(accumulator["formula_match_count"]),
        "formula_mismatch_count": formula_mismatch_count,
        "formula_residue_zero_count": formula_residue_zero_count,
        "formula_unavailable_count": formula_unavailable_count,
        "odd_prime_formula_count": int(accumulator["applicability_class_counts"].get("odd_prime_order_formula", 0)),
        "q2_exception_formula_count": int(accumulator["applicability_class_counts"].get("q2_exception_formula", 0)),
        "zsigmondy_exception_formula_count": int(
            accumulator["applicability_class_counts"].get("zsigmondy_2_6_formula", 0)
        ),
        "applicability_class_counts": dict(sorted(accumulator["applicability_class_counts"].items())),
        "repair_class_counts": dict(sorted(accumulator["repair_class_counts"].items())),
        "formula_status_counts": dict(sorted(accumulator["formula_status_counts"].items())),
        "residue_formula_digest_manifest": {
            "row_schema": "period_noncollapse_residue_formula_digest_v0",
            "row_count": int(accumulator["formula_check_count"]),
            "formula_rows_sha256": _sha256(accumulator["formula_digest_rows"]),
            "full_row_policy": "The builder reconstructs every residue formula on each run; committed JSON stores digest manifest, representative samples, and mismatch/zero/unavailable rows.",
        },
        "residue_shape_count": len(proof_shape_rows),
        "residue_shape_digest": _sha256(proof_shape_rows),
        "numeric_residue_shape_count": len(numeric_shape_rows),
        "numeric_residue_shape_digest": _sha256(numeric_shape_rows),
        "multi_minimal_numeric_shape_count": sum(
            1 for row in numeric_shape_rows if row["repair_class"] == "multi_minimal_residue_nonzero_certificate"
        ),
        "sample_shapes": proof_shape_rows,
        "sample_numeric_shapes": sample_numeric_shapes,
        "sample_formulas": list(accumulator["sample_formulas"].values()),
        "mismatch_samples": list(accumulator["mismatch_samples"]),
        "zero_samples": list(accumulator["zero_samples"]),
        "unavailable_samples": list(accumulator["unavailable_samples"]),
        "unresolved_shape_count": sum(
            1
            for row in proof_shape_rows
            if row["formula_mismatch_count"] or row["formula_zero_count"]
        )
        + (1 if formula_unavailable_count else 0),
        "first_lean_target": "residue_formula_certificate_blocks_collapse",
        "current_decisive_blocker": current_decisive_blocker,
        "claim_boundary": "residue formulas explain bounded local-layer certificates; they do not prove the universal finite theorem or Erdos #257",
    }


def _new_canonical_witness_selector_accumulator() -> dict[str, Any]:
    return {
        "checked_case_count": 0,
        "selector_check_count": 0,
        "primitive_witness_count": 0,
        "n0_2_q2_exception_count": 0,
        "n0_6_q3_exception_count": 0,
        "singleton_minimal_count": 0,
        "multi_minimal_count": 0,
        "no_witness_count": 0,
        "valuation_deficit_failure_count": 0,
        "residue_formula_fallback_needed_count": 0,
        "selection_rank_over_one_count": 0,
        "selected_q_distribution": Counter(),
        "selector_digest_rows": [],
        "proof_shapes": {},
        "sample_rows": {},
        "disconfirming_rows": [],
    }


def _canonical_witness_candidates(
    *,
    base: int,
    subset: Sequence[int],
    period: int,
    prime: int,
) -> list[dict[str, Any]]:
    active_p_exponent = _valuation(period, prime)
    active_n = [n for n in subset if _valuation(n, prime) == active_p_exponent]
    maximal_active_n = _divisibility_maximal_elements(active_n)
    m_p = _m_p(base, period, prime)
    _, a_l = _b_and_a_l(base, subset, period)

    def _with_metrics(row: Mapping[str, Any]) -> dict[str, Any]:
        q = int(row["prime_q"])
        return {
            **row,
            "v_q_M_p": _valuation(m_p, q),
            "v_q_A_L": _valuation(a_l, q),
            "valuation_deficit": _valuation(m_p, q) - _valuation(a_l, q),
        }

    candidates: list[dict[str, Any]] = []
    for n0_rank, n0 in enumerate(maximal_active_n, start=1):
        exception_class = _zsigmondy_exception_class(base, n0)
        if exception_class == "zsigmondy_exception_n2_base_plus_one_power_of_two":
            q = 2
            candidates.append(
                _with_metrics(
                    {
                        "prime_q": q,
                        "q_factor_exponent_in_b_to_n0_minus_1": _valuation(base**n0 - 1, q),
                        "ord_q_b": _order_dividing_period(base, q, n0, _factorint(n0)),
                        "primitive_prime_for_b_to_n0_minus_1": False,
                        "candidate_n0": n0,
                        "exception_class": exception_class,
                        "q_divides_L_over_n0": (period // n0) % q == 0,
                        "selection_hint": "n0_2_q2_exception",
                        "canonical_n0_rank": n0_rank,
                    }
                )
            )
            continue
        if exception_class == "zsigmondy_exception_base2_n6":
            q = 3
            candidates.append(
                _with_metrics(
                    {
                        "prime_q": q,
                        "q_factor_exponent_in_b_to_n0_minus_1": _valuation(base**n0 - 1, q),
                        "ord_q_b": _order_dividing_period(base, q, n0, _factorint(n0)),
                        "primitive_prime_for_b_to_n0_minus_1": False,
                        "candidate_n0": n0,
                        "exception_class": exception_class,
                        "q_divides_L_over_n0": (period // n0) % q == 0,
                        "selection_hint": "n0_6_q3_exception",
                        "canonical_n0_rank": n0_rank,
                    }
                )
            )
            continue
        for candidate in _primitive_prime_candidates(base, n0):
            if not candidate["primitive_prime_for_b_to_n0_minus_1"]:
                continue
            q = int(candidate["prime_q"])
            candidates.append(
                _with_metrics(
                    {
                        **candidate,
                        "candidate_n0": n0,
                        "exception_class": None,
                        "q_divides_L_over_n0": (period // n0) % q == 0,
                        "selection_hint": "primitive_witness",
                        "canonical_n0_rank": n0_rank,
                    }
                )
            )
    return sorted(
        candidates,
        key=lambda row: (
            int(row["canonical_n0_rank"]),
            int(row["candidate_n0"]),
            int(row["prime_q"]),
        ),
    )


def _canonical_selector_certificate_passes(certificate: Mapping[str, Any]) -> bool:
    return (
        certificate["certificate_status"] == "local_layer_certificate_pass"
        and len(certificate["minimal_layer"]) == 1
        and int(certificate["valuation_deficit"]) > 0
    )


def _canonical_selector_compact_row(certificate: Mapping[str, Any]) -> dict[str, Any]:
    witness = certificate["selected_witness"]
    return {
        "case_id": certificate["case_id"],
        "b": certificate["b"],
        "F": certificate["F"],
        "L": certificate["L"],
        "p": certificate["p"],
        "q": certificate["q"],
        "candidate_n0": witness.get("candidate_n0"),
        "selected_witness_family": witness.get("selection_hint"),
        "exception_class": witness.get("exception_class"),
        "ord_q_b": witness.get("ord_q_b"),
        "canonical_n0_rank": witness.get("canonical_n0_rank"),
        "selection_rank": certificate["selection_rank"],
        "minimal_layer": certificate["minimal_layer"],
        "minimal_valuation": certificate["minimal_valuation"],
        "residue_nonzero": certificate["residue_nonzero"],
        "valuation_deficit": certificate["valuation_deficit"],
        "selector_status": (
            "singleton_minimal_witness"
            if _canonical_selector_certificate_passes(certificate)
            else "residue_formula_fallback_needed"
        ),
    }


def _canonical_selector_shape_key(certificate: Mapping[str, Any]) -> tuple[str, str]:
    witness_family = str(certificate["selected_witness"].get("selection_hint"))
    active_prime_role = (
        f"p={certificate['p']}" if witness_family == "n0_6_q3_exception" else "all_active_primes"
    )
    return (witness_family, active_prime_role)


def _canonical_selector_shape_row(key: tuple[str, str], row: Mapping[str, Any]) -> dict[str, Any]:
    witness_family, active_prime_role = key
    if witness_family == "primitive_witness":
        proof_obligation = (
            "Use primitive order d=n0 and divisibility maximality to make n0 the unique minimal q-adic summand."
        )
    elif witness_family == "n0_2_q2_exception":
        proof_obligation = (
            "For n0=2 with b+1 a power of two, prove q=2 gives a singleton minimal layer."
        )
    elif active_prime_role == "p=2":
        proof_obligation = (
            "For (b,n0)=(2,6) and active p=2, prove q=3 makes n0=6 the singleton minimal layer."
        )
    else:
        proof_obligation = (
            "For (b,n0)=(2,6) and active p=3, prove q=3 makes n0=6 the singleton minimal layer."
        )
    return {
        "selector_shape_id": _shape_id("cws", key),
        "selected_witness_family": witness_family,
        "active_prime_role": active_prime_role,
        "row_count": int(row["row_count"]),
        "sample_case_ids": list(row["sample_case_ids"]),
        "proof_obligation": proof_obligation,
    }


def _record_canonical_shape(
    accumulator: dict[str, Any],
    certificate: Mapping[str, Any],
) -> None:
    key = _canonical_selector_shape_key(certificate)
    row = accumulator["proof_shapes"].setdefault(
        key,
        {
            "row_count": 0,
            "sample_case_ids": [],
        },
    )
    row["row_count"] += 1
    if len(row["sample_case_ids"]) < 8:
        row["sample_case_ids"].append(certificate["case_id"])


def _sample_key_for_canonical_selector(certificate: Mapping[str, Any]) -> str | None:
    witness_family = str(certificate["selected_witness"].get("selection_hint"))
    if certificate["case_id"] == "b2_F3-6" and certificate["p"] == 3:
        return "b2_F3-6_p3_q3_exception"
    if certificate["case_id"] == "b2_F6" and certificate["p"] == 2:
        return "b2_F6_p2_q3_exception"
    if witness_family == "primitive_witness":
        return "primitive_witness"
    if witness_family == "n0_2_q2_exception":
        return "n0_2_q2_exception"
    if witness_family == "n0_6_q3_exception":
        return "n0_6_q3_exception"
    return None


def _accumulate_canonical_witness_selector(
    accumulator: dict[str, Any],
    row: Mapping[str, Any],
) -> None:
    accumulator["checked_case_count"] += 1
    case_id = str(row["case_id"])
    base = int(row["b"])
    subset = tuple(int(n) for n in row["F"])
    period = int(row["L"])
    for check in row["valuation_witness_checks"]:
        prime = int(check["prime"])
        accumulator["selector_check_count"] += 1
        candidates = _canonical_witness_candidates(
            base=base,
            subset=subset,
            period=period,
            prime=prime,
        )
        if not candidates:
            accumulator["no_witness_count"] += 1
            accumulator["residue_formula_fallback_needed_count"] += 1
            if len(accumulator["disconfirming_rows"]) < 16:
                accumulator["disconfirming_rows"].append(
                    {
                        "case_id": case_id,
                        "b": base,
                        "F": list(subset),
                        "L": period,
                        "p": prime,
                        "selector_status": "no_canonical_witness",
                        "attempts": [],
                    }
                )
            continue

        attempts: list[dict[str, Any]] = []
        selected_certificate: dict[str, Any] | None = None
        for rank, candidate in enumerate(candidates, start=1):
            certificate = _local_layer_certificate_from_witness(
                base=base,
                subset=subset,
                period=period,
                prime=prime,
                witness=candidate,
                witness_source="canonical_witness_selector",
                repair_class="canonical_singleton_minimal_witness",
                selection_rank=rank,
            )
            certificate["case_id"] = case_id
            attempts.append(_canonical_selector_compact_row(certificate))
            if _canonical_selector_certificate_passes(certificate):
                selected_certificate = certificate
                break

        if selected_certificate is None:
            accumulator["residue_formula_fallback_needed_count"] += 1
            first_attempt = attempts[0]
            if len(first_attempt["minimal_layer"]) > 1:
                accumulator["multi_minimal_count"] += 1
            if int(first_attempt["valuation_deficit"]) <= 0 or not first_attempt["residue_nonzero"]:
                accumulator["valuation_deficit_failure_count"] += 1
            if len(accumulator["disconfirming_rows"]) < 16:
                accumulator["disconfirming_rows"].append(
                    {
                        "case_id": case_id,
                        "b": base,
                        "F": list(subset),
                        "L": period,
                        "p": prime,
                        "selector_status": "canonical_witness_failed",
                        "attempts": attempts[:4],
                    }
                )
            continue

        compact_row = _canonical_selector_compact_row(selected_certificate)
        witness_family = str(selected_certificate["selected_witness"].get("selection_hint"))
        accumulator["singleton_minimal_count"] += 1
        accumulator["selected_q_distribution"][str(selected_certificate["q"])] += 1
        accumulator["selector_digest_rows"].append(compact_row)
        if selected_certificate["selection_rank"] > 1:
            accumulator["selection_rank_over_one_count"] += 1
        if witness_family == "primitive_witness":
            accumulator["primitive_witness_count"] += 1
        elif witness_family == "n0_2_q2_exception":
            accumulator["n0_2_q2_exception_count"] += 1
        elif witness_family == "n0_6_q3_exception":
            accumulator["n0_6_q3_exception_count"] += 1
        _record_canonical_shape(accumulator, selected_certificate)
        sample_key = _sample_key_for_canonical_selector(selected_certificate)
        if sample_key:
            accumulator["sample_rows"].setdefault(sample_key, selected_certificate)


def _finalize_canonical_witness_selector_kernel(accumulator: Mapping[str, Any]) -> dict[str, Any]:
    proof_shape_rows = [
        _canonical_selector_shape_row(key, row)
        for key, row in sorted(
            accumulator["proof_shapes"].items(),
            key=lambda item: (item[0][0], item[0][1]),
        )
    ]
    selector_check_count = int(accumulator["selector_check_count"])
    singleton_minimal_count = int(accumulator["singleton_minimal_count"])
    residue_formula_fallback_needed_count = int(accumulator["residue_formula_fallback_needed_count"])
    route_is_clean = (
        selector_check_count > 0
        and singleton_minimal_count == selector_check_count
        and residue_formula_fallback_needed_count == 0
        and int(accumulator["no_witness_count"]) == 0
        and int(accumulator["multi_minimal_count"]) == 0
        and int(accumulator["valuation_deficit_failure_count"]) == 0
    )
    proof_kernel_route_status = (
        "proof_kernel_split_reduced_to_canonical_witness_selector_pending_lean"
        if route_is_clean
        else "canonical_witness_selector_partial_residue_formula_fallback_active"
    )
    current_decisive_blocker = (
        "Lean-check canonical_witness_singleton_minimality_supplies_witness_existence and the two Zsigmondy exception handlers."
        if route_is_clean
        else "Inspect disconfirming selector rows; keep residue_formula_kernel active for unresolved rows."
    )
    return {
        "route_id": "period_noncollapse_canonical_witness_selector_kernel",
        "route_status": "PASS" if route_is_clean else "GAP",
        "proof_kernel_route_status": proof_kernel_route_status,
        "selector_check_count": selector_check_count,
        "primitive_witness_count": int(accumulator["primitive_witness_count"]),
        "n0_2_q2_exception_count": int(accumulator["n0_2_q2_exception_count"]),
        "n0_6_q3_exception_count": int(accumulator["n0_6_q3_exception_count"]),
        "singleton_minimal_count": singleton_minimal_count,
        "multi_minimal_count": int(accumulator["multi_minimal_count"]),
        "no_witness_count": int(accumulator["no_witness_count"]),
        "valuation_deficit_failure_count": int(accumulator["valuation_deficit_failure_count"]),
        "residue_formula_fallback_needed_count": residue_formula_fallback_needed_count,
        "selection_rank_over_one_count": int(accumulator["selection_rank_over_one_count"]),
        "selected_q_distribution": dict(
            sorted(
                accumulator["selected_q_distribution"].items(),
                key=lambda item: int(item[0]),
            )
        ),
        "selector_digest_manifest": {
            "row_schema": "period_noncollapse_canonical_witness_selector_digest_v0",
            "row_count": selector_check_count,
            "selector_rows_sha256": _sha256(accumulator["selector_digest_rows"]),
            "full_row_policy": "The builder reconstructs every canonical witness selector row on each run; committed JSON stores digest manifest, proof shapes, samples, and disconfirming rows.",
        },
        "proof_shape_count": len(proof_shape_rows),
        "proof_shape_digest": _sha256(proof_shape_rows),
        "sample_shapes": proof_shape_rows,
        "sample_rows": list(accumulator["sample_rows"].values()),
        "disconfirming_rows": list(accumulator["disconfirming_rows"]),
        "first_lean_target": "canonical_witness_singleton_minimality_supplies_witness_existence",
        "current_decisive_blocker": current_decisive_blocker,
        "claim_boundary": "canonical witness selector is checked on the bounded corpus; it is not a Lean proof or universal finite theorem proof",
    }


def _record_exception_2_6_fragility(
    accumulator: dict[str, Any],
    *,
    base: int,
    subset: Sequence[int],
    period: int,
    a_l: int,
    check: Mapping[str, Any],
    case_id: str,
) -> None:
    prime = int(check["prime"])
    if prime not in {2, 3}:
        return
    q = 3
    n0 = 6
    m_p = _m_p(base, period, prime)
    summand_valuations = _summand_valuations(base, subset, period, q)
    min_valuation = min(summand_valuations.values())
    minimal_ns = sorted(n for n, value in summand_valuations.items() if value == min_valuation)
    deficit = _valuation(m_p, q) - _valuation(a_l, q)
    check_id = "check_exception_2_6_p2" if prime == 2 else "check_exception_2_6_p3"
    _record_fragility_check(
        accumulator,
        check_id=check_id,
        ok=base == 2 and n0 in subset and minimal_ns == [n0] and deficit > 0,
        case_id=case_id,
        detail={
            "base": base,
            "F": list(subset),
            "prime": prime,
            "q": q,
            "minimal_ns": minimal_ns,
            "valuation_deficit": deficit,
        },
    )


def _accumulate_proof_fragility(accumulator: dict[str, Any], row: Mapping[str, Any]) -> None:
    case_id = str(row["case_id"])
    base = int(row["b"])
    subset = tuple(int(n) for n in row["F"])
    period = int(row["L"])
    denominator = int(row["Q"])
    order = int(row["ord_Q_b"])
    b_to_l_minus_one, a_l = _b_and_a_l(base, subset, period)

    accumulator["checked_case_count"] += 1
    expected_denominator = b_to_l_minus_one // math.gcd(a_l, b_to_l_minus_one)
    _record_fragility_check(
        accumulator,
        check_id="check_Q_equals_B_div_gcd",
        ok=denominator == expected_denominator,
        case_id=case_id,
        detail={"Q": denominator, "expected_Q": expected_denominator},
    )

    if period == 1:
        accumulator["targeted_edge_case_ids"].add(case_id)
        _record_fragility_check(
            accumulator,
            check_id="check_L_equals_1_edge",
            ok=order == 1 and not row["collapse_divisor_checks"] and not row["valuation_witness_checks"],
            case_id=case_id,
            detail={"ord_Q_b": order, "Q": denominator},
        )

    if denominator == 1:
        accumulator["targeted_edge_case_ids"].add(case_id)
        _record_fragility_check(
            accumulator,
            check_id="check_Q_equals_1_edge",
            ok=period == 1 and order == 1,
            case_id=case_id,
            detail={"L": period, "ord_Q_b": order},
        )

    for check in row["valuation_witness_checks"]:
        accumulator["prime_component_check_count"] += 1
        witness = check.get("selected_witness")
        prime = int(check["prime"])
        if witness is None:
            _record_fragility_check(
                accumulator,
                check_id="check_unique_minimal_summand",
                ok=False,
                case_id=case_id,
                detail={"prime": prime, "reason": "missing selected witness"},
            )
            continue

        q = int(witness["prime_q"])
        n0 = int(witness["candidate_n0"])
        summand_valuations = _summand_valuations(base, subset, period, q)
        min_valuation = min(summand_valuations.values())
        minimal_ns = sorted(n for n, value in summand_valuations.items() if value == min_valuation)
        a_l_valuation = _valuation(a_l, q)
        _record_fragility_check(
            accumulator,
            check_id="check_unique_minimal_summand",
            ok=(
                minimal_ns == [n0]
                and a_l_valuation == min_valuation
                and a_l_valuation == int(witness["v_q_A_L"])
            ),
            case_id=case_id,
            detail={
                "prime": prime,
                "q": q,
                "n0": n0,
                "minimal_ns": minimal_ns,
                "v_q_A_L": a_l_valuation,
                "witness_v_q_A_L": int(witness["v_q_A_L"]),
            },
        )

        active_p_valuation = _valuation(period, prime)
        escaped_active_multiples = [
            n
            for n in subset
            if n != n0 and n % n0 == 0 and _valuation(n, prime) == active_p_valuation
        ]
        _record_fragility_check(
            accumulator,
            check_id="check_no_active_multiple_escapes_maximality",
            ok=not escaped_active_multiples,
            case_id=case_id,
            detail={
                "prime": prime,
                "n0": n0,
                "escaped_active_multiples": escaped_active_multiples,
            },
        )

        exception_class = witness.get("exception_class")
        if exception_class == "zsigmondy_exception_n2_base_plus_one_power_of_two":
            accumulator["targeted_edge_case_ids"].add(case_id)
            _record_fragility_check(
                accumulator,
                check_id="check_exception_n0_2_power_of_two",
                ok=(
                    base % 2 == 1
                    and n0 == 2
                    and q == 2
                    and prime == 2
                    and _is_power_of_two(base + 1)
                    and int(witness["valuation_deficit"]) > 0
                ),
                case_id=case_id,
                detail={
                    "base": base,
                    "prime": prime,
                    "q": q,
                    "n0": n0,
                    "base_plus_one": base + 1,
                    "valuation_deficit": int(witness["valuation_deficit"]),
                },
            )
        elif exception_class == "zsigmondy_exception_base2_n6":
            accumulator["targeted_edge_case_ids"].add(case_id)
            _record_exception_2_6_fragility(
                accumulator,
                base=base,
                subset=subset,
                period=period,
                a_l=a_l,
                check=check,
                case_id=case_id,
            )


def _finalize_proof_fragility(accumulator: Mapping[str, Any]) -> dict[str, Any]:
    failure_count = int(accumulator["failure_count"])
    return {
        "suite_id": "period_noncollapse_proof_fragility_suite_v0",
        "suite_status": "PASS" if failure_count == 0 else "FAIL",
        "checked_case_count": int(accumulator["checked_case_count"]),
        "prime_component_check_count": int(accumulator["prime_component_check_count"]),
        "assertion_count": int(accumulator["assertion_count"]),
        "failure_count": failure_count,
        "check_counts": dict(sorted(accumulator["check_counts"].items())),
        "failure_check_counts": dict(sorted(accumulator["failure_check_counts"].items())),
        "targeted_edge_case_count": len(accumulator["targeted_edge_case_ids"]),
        "targeted_edge_case_ids": sorted(accumulator["targeted_edge_case_ids"])[:24],
        "failure_samples": list(accumulator["failure_samples"]),
        "failure_interpretation": (
            "No local proof-route assumption failures were found on the bounded corpus."
            if failure_count == 0
            else "Bounded theorem checks still pass, but the paper proof route has named local-assumption failures that need a sharper existence/exception kernel."
        ),
        "claim_boundary": "fragility checks test the proof route's local assumptions on the bounded corpus; they are not a proof of the finite theorem",
    }


def _new_local_layer_accumulator() -> dict[str, Any]:
    return {
        "checked_case_count": 0,
        "certificate_check_count": 0,
        "status_counts": Counter(),
        "repair_class_counts": Counter(),
        "witness_source_counts": Counter(),
        "prior_unique_minimal_failure_count": 0,
        "prior_unique_minimal_failure_repaired_count": 0,
        "certificate_digest_rows": [],
        "sample_certificates": {},
        "obstruction_class_counts": Counter(),
        "sample_obstructions": [],
        "unresolved_certificates": [],
        "counterexample_or_bug_certificates": [],
    }


def _sample_key_for_local_layer(certificate: Mapping[str, Any]) -> str | None:
    repair_class = str(certificate["repair_class"])
    if repair_class == "unique_minimal_certificate":
        return "unique_minimal_certificate"
    if repair_class == "multi_minimal_residue_nonzero_certificate":
        return "multi_minimal_residue_nonzero_certificate"
    if repair_class == "proof_friendly_reselected_witness":
        return "proof_friendly_reselected_witness"
    if repair_class == "exception_specific_q3_certificate":
        return "exception_specific_q3_certificate"
    if repair_class == "residue_zero_unresolved":
        return "residue_zero_unresolved"
    if repair_class == "counterexample_or_bug":
        return "counterexample_or_bug"
    return None


def _select_local_layer_certificate(
    *,
    row: Mapping[str, Any],
    check: Mapping[str, Any],
) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    case_id = str(row["case_id"])
    base = int(row["b"])
    subset = tuple(int(n) for n in row["F"])
    period = int(row["L"])
    prime = int(check["prime"])
    attempts: list[dict[str, Any]] = []
    if check["collapse_detected"] or not check["equivalence_holds"]:
        witness = check.get("selected_witness") or {
            "prime_q": 1,
            "candidate_n0": 0,
            "exception_class": None,
            "v_q_M_p": 0,
            "v_q_A_L": 0,
            "valuation_deficit": 0,
        }
        certificate = {
            "case_id": case_id,
            "b": base,
            "F": list(subset),
            "L": period,
            "p": prime,
            "q": int(witness["prime_q"]),
            "M_p_sha256": _int_sha256(_m_p(base, period, prime)),
            "M_p_digit_count_estimate": _int_digit_count_estimate(_m_p(base, period, prime)),
            "A_L_sha256": _int_sha256(_b_and_a_l(base, subset, period)[1]),
            "A_L_digit_count_estimate": _int_digit_count_estimate(_b_and_a_l(base, subset, period)[1]),
            "selected_witness_kind": "counterexample_or_bug",
            "selected_witness": dict(witness),
            "witness_source": "collapse_or_equivalence_failure",
            "selection_rank": 0,
            "minimal_layer": [],
            "minimal_valuation": None,
            "minimal_layer_residue_mod_q": None,
            "normalized_minimal_layer_terms_mod_q": [],
            "residue_nonzero": False,
            "v_q_M_p": int(witness.get("v_q_M_p", 0)),
            "v_q_A_L_actual": int(witness.get("v_q_A_L", 0)),
            "v_q_A_L_or_certified_value": int(witness.get("v_q_A_L", 0)),
            "valuation_deficit": int(witness.get("valuation_deficit", 0)),
            "certificate_status": "counterexample_or_bug",
            "repair_class": "counterexample_or_bug",
            "prior_unique_minimal_failed": True,
            "claim_boundary": "counterexample_or_bug row blocks proof-route promotion",
        }
        return certificate, attempts

    selected = check.get("selected_witness")
    first_full_attempt: dict[str, Any] | None = None
    if selected is not None:
        selected_certificate = _local_layer_certificate_from_witness(
            base=base,
            subset=subset,
            period=period,
            prime=prime,
            witness=selected,
            witness_source="selected_valuation_witness",
            repair_class="unique_minimal_certificate",
            selection_rank=0,
        )
        selected_certificate["case_id"] = case_id
        first_full_attempt = selected_certificate
        if len(selected_certificate["minimal_layer"]) > 1:
            selected_certificate["repair_class"] = (
                "multi_minimal_residue_nonzero_certificate"
                if selected_certificate["certificate_status"] == "local_layer_certificate_pass"
                else "residue_zero_unresolved"
            )
        attempts.append(_compact_local_layer_certificate(selected_certificate))
        if selected_certificate["certificate_status"] == "local_layer_certificate_pass":
            return selected_certificate, attempts

    candidates = _local_layer_candidate_witnesses(
        base=base,
        subset=subset,
        period=period,
        prime=prime,
    )
    selected_key = None
    if selected is not None:
        selected_key = (int(selected["prime_q"]), int(selected["candidate_n0"]))

    reselected_singleton: dict[str, Any] | None = None
    reselected_residue: dict[str, Any] | None = None
    q3_exception: dict[str, Any] | None = None
    for rank, candidate in enumerate(candidates, start=1):
        candidate_key = (int(candidate["prime_q"]), int(candidate["candidate_n0"]))
        if selected_key is not None and candidate_key == selected_key and candidate.get("selection_hint") != "exception_specific_q3":
            continue
        repair_class = (
            "exception_specific_q3_certificate"
            if candidate.get("selection_hint") == "exception_specific_q3"
            else "proof_friendly_reselected_witness"
        )
        certificate = _local_layer_certificate_from_witness(
            base=base,
            subset=subset,
            period=period,
            prime=prime,
            witness=candidate,
            witness_source=str(candidate.get("selection_hint", "candidate_reselection")),
            repair_class=repair_class,
            selection_rank=rank,
        )
        certificate["case_id"] = case_id
        if first_full_attempt is None:
            first_full_attempt = certificate
        attempts.append(_compact_local_layer_certificate(certificate))
        if certificate["certificate_status"] != "local_layer_certificate_pass":
            continue
        if repair_class == "exception_specific_q3_certificate":
            if q3_exception is None:
                q3_exception = certificate
            continue
        if len(certificate["minimal_layer"]) == 1 and reselected_singleton is None:
            reselected_singleton = certificate
        if reselected_residue is None:
            reselected_residue = certificate

    if reselected_singleton is not None:
        return reselected_singleton, attempts
    if reselected_residue is not None:
        return reselected_residue, attempts
    if q3_exception is not None:
        return q3_exception, attempts

    unresolved = first_full_attempt if first_full_attempt is not None else {
        "case_id": case_id,
        "b": base,
        "F": list(subset),
        "L": period,
        "p": prime,
        "q": None,
        "minimal_layer": [],
        "minimal_valuation": None,
        "minimal_layer_residue_mod_q": None,
        "residue_nonzero": False,
        "v_q_M_p": 0,
        "v_q_A_L_or_certified_value": 0,
        "valuation_deficit": 0,
        "certificate_status": "residue_zero_unresolved",
        "repair_class": "residue_zero_unresolved",
        "witness_source": "no_candidate_witness",
        "selected_witness": {},
        "prior_unique_minimal_failed": True,
        "M_p_sha256": _int_sha256(_m_p(base, period, prime)),
        "A_L_sha256": _int_sha256(_b_and_a_l(base, subset, period)[1]),
    }
    unresolved = dict(unresolved)
    unresolved["certificate_status"] = "residue_zero_unresolved"
    unresolved["repair_class"] = "residue_zero_unresolved"
    return unresolved, attempts


def _accumulate_local_layer_certificates(
    accumulator: dict[str, Any],
    row: Mapping[str, Any],
    residue_formula_accumulator: dict[str, Any],
) -> None:
    accumulator["checked_case_count"] += 1
    residue_formula_accumulator["checked_case_count"] += 1
    for check in row["valuation_witness_checks"]:
        certificate, attempts = _select_local_layer_certificate(row=row, check=check)
        compact_certificate = _compact_local_layer_certificate(certificate)
        accumulator["certificate_check_count"] += 1
        accumulator["status_counts"][certificate["certificate_status"]] += 1
        accumulator["repair_class_counts"][certificate["repair_class"]] += 1
        accumulator["witness_source_counts"][certificate["witness_source"]] += 1
        accumulator["certificate_digest_rows"].append(compact_certificate)
        _accumulate_residue_formula(residue_formula_accumulator, certificate)
        sample_key = _sample_key_for_local_layer(certificate)
        if sample_key:
            accumulator["sample_certificates"].setdefault(sample_key, certificate)
        if certificate["prior_unique_minimal_failed"]:
            accumulator["prior_unique_minimal_failure_count"] += 1
            obstruction_class = (
                "multi_minimal_layer_selected_witness"
                if len(certificate.get("minimal_layer", [])) > 1
                else "selected_witness_failed_unique_minimal_assumption"
            )
            accumulator["obstruction_class_counts"][obstruction_class] += 1
            if certificate["certificate_status"] == "local_layer_certificate_pass":
                accumulator["prior_unique_minimal_failure_repaired_count"] += 1
            if len(accumulator["sample_obstructions"]) < 12:
                accumulator["sample_obstructions"].append(
                    {
                        "obstruction_id": f"{certificate['case_id']}:p{certificate['p']}:q{certificate['q']}",
                        "case_id": certificate["case_id"],
                        "failure_check": "check_unique_minimal_summand",
                        "p": certificate["p"],
                        "q": certificate["q"],
                        "n0": certificate["selected_witness"].get("candidate_n0"),
                        "minimal_ns": certificate["minimal_layer"],
                        "selected_witness": certificate["selected_witness"],
                        "repair_attempts": attempts[:6],
                        "final_certificate_status": certificate["certificate_status"],
                        "repair_class": certificate["repair_class"],
                    }
                )
        if certificate["certificate_status"] == "residue_zero_unresolved" and len(accumulator["unresolved_certificates"]) < 12:
            accumulator["unresolved_certificates"].append(certificate)
        if certificate["certificate_status"] == "counterexample_or_bug" and len(accumulator["counterexample_or_bug_certificates"]) < 12:
            accumulator["counterexample_or_bug_certificates"].append(certificate)


def _finalize_local_layer_certificate_kernel(
    accumulator: Mapping[str, Any],
    proof_fragility: Mapping[str, Any],
) -> dict[str, Any]:
    residue_zero_unresolved_count = int(accumulator["repair_class_counts"].get("residue_zero_unresolved", 0))
    counterexample_or_bug_count = int(accumulator["repair_class_counts"].get("counterexample_or_bug", 0))
    route_is_clean = residue_zero_unresolved_count == 0 and counterexample_or_bug_count == 0
    prior_fragility_failure_count = int(
        proof_fragility["failure_check_counts"].get(
            "check_unique_minimal_summand",
            accumulator["prior_unique_minimal_failure_count"],
        )
    )
    return {
        "route_id": "period_noncollapse_local_layer_certificate_kernel",
        "route_status": "PASS" if route_is_clean else "GAP",
        "proof_kernel_route_status": (
            "proof_kernel_split_repaired_by_local_layer_certificates_pending_lean"
            if route_is_clean
            else "proof_kernel_split_blocked_by_residue_zero_rows"
        ),
        "prior_unique_minimal_failure_count": prior_fragility_failure_count,
        "prior_unique_minimal_failure_repaired_count": int(
            accumulator["prior_unique_minimal_failure_repaired_count"]
        ),
        "checked_case_count": int(accumulator["checked_case_count"]),
        "certificate_check_count": int(accumulator["certificate_check_count"]),
        "unique_minimal_certificate_count": int(
            accumulator["repair_class_counts"].get("unique_minimal_certificate", 0)
        ),
        "multi_minimal_residue_nonzero_count": int(
            accumulator["repair_class_counts"].get("multi_minimal_residue_nonzero_certificate", 0)
        ),
        "proof_friendly_reselection_count": int(
            accumulator["repair_class_counts"].get("proof_friendly_reselected_witness", 0)
        ),
        "exception_specific_q3_certificate_count": int(
            accumulator["repair_class_counts"].get("exception_specific_q3_certificate", 0)
        ),
        "residue_zero_unresolved_count": residue_zero_unresolved_count,
        "counterexample_or_bug_count": counterexample_or_bug_count,
        "status_counts": dict(sorted(accumulator["status_counts"].items())),
        "repair_class_counts": dict(sorted(accumulator["repair_class_counts"].items())),
        "witness_source_counts": dict(sorted(accumulator["witness_source_counts"].items())),
        "certificate_digest_manifest": {
            "row_schema": "period_noncollapse_local_layer_certificate_digest_v0",
            "row_count": int(accumulator["certificate_check_count"]),
            "certificate_rows_sha256": _sha256(accumulator["certificate_digest_rows"]),
            "full_row_policy": "The builder verifies every local-layer row on each run; committed JSON stores digest manifest, representative samples, and unresolved/counterexample rows.",
        },
        "sample_certificates": list(accumulator["sample_certificates"].values()),
        "obstruction_zoo": {
            "obstruction_class_counts": dict(sorted(accumulator["obstruction_class_counts"].items())),
            "sample_obstructions": list(accumulator["sample_obstructions"]),
            "interpretation": "Prior unique-minimal proof-route failures are retained as obstruction rows and linked to their local-layer repair certificates.",
        },
        "unresolved_certificates": list(accumulator["unresolved_certificates"]),
        "counterexample_or_bug_certificates": list(accumulator["counterexample_or_bug_certificates"]),
        "first_lean_target": "local_layer_residue_nonzero_implies_sum_valuation",
        "current_decisive_blocker": (
            "Lean-check the local-layer certificate kernel; witness existence remains a separate paper/referee target."
            if route_is_clean
            else "Inspect residue-zero or counterexample rows before referee/provider work."
        ),
        "claim_boundary": "local-layer certificates repair the bounded proof route; they do not prove the universal finite theorem or Erdos #257",
    }


def _fragility_status_normalization(
    *,
    proof_fragility: Mapping[str, Any],
    local_layer: Mapping[str, Any],
    proof_closure: Mapping[str, Any] | None = None,
) -> dict[str, Any]:
    raw_legacy_failure_count = int(proof_fragility["failure_count"])
    routed_failure_count = int(local_layer["prior_unique_minimal_failure_count"])
    repaired_failure_count = int(
        local_layer["prior_unique_minimal_failure_repaired_count"]
    )
    residue_zero_unresolved_count = int(local_layer["residue_zero_unresolved_count"])
    counterexample_or_bug_count = int(local_layer["counterexample_or_bug_count"])
    open_after_repair_count = (
        max(0, raw_legacy_failure_count - repaired_failure_count)
        + residue_zero_unresolved_count
        + counterexample_or_bug_count
    )
    all_repaired = (
        raw_legacy_failure_count == routed_failure_count
        and raw_legacy_failure_count == repaired_failure_count
        and residue_zero_unresolved_count == 0
        and counterexample_or_bug_count == 0
    )
    theorem_gap_status = (
        proof_closure["proof_status"] if proof_closure is not None else None
    )
    return {
        "schema_version": "period_noncollapse_fragility_status_normalization_v0",
        "status": (
            "raw_failures_accounted_by_local_layer_route"
            if all_repaired
            else "open_fragility_rows_after_repair_route"
        ),
        "operator_display_status": "REPAIRED" if all_repaired else "OPEN",
        "raw_legacy_fragility_suite_status": proof_fragility["suite_status"],
        "raw_legacy_fragility_failure_count": raw_legacy_failure_count,
        "raw_legacy_failure_check_counts": dict(
            proof_fragility["failure_check_counts"]
        ),
        "routed_fragility_failure_count": routed_failure_count,
        "routed_repaired_fragility_failure_count": repaired_failure_count,
        "open_fragility_failure_count_after_repair_route": open_after_repair_count,
        "repair_route": "local_layer_multi_minimal_residue_nonzero_certificate",
        "repair_route_status": local_layer["route_status"],
        "multi_minimal_residue_nonzero_certificate_count": int(
            local_layer["multi_minimal_residue_nonzero_count"]
        ),
        "residue_zero_unresolved_count": residue_zero_unresolved_count,
        "counterexample_or_bug_count": counterexample_or_bug_count,
        "theorem_gap_status": theorem_gap_status,
        "theorem_gap_boundary": (
            "Repaired bounded fragility rows do not close the candidate finite "
            "theorem; closure lemmas remain pending referee/Lean unless their "
            "own proof-authority receipts say otherwise."
        ),
    }


def _finite_search_results() -> dict[str, Any]:
    case_rows: list[dict[str, Any]] = []
    detailed_sample_cases: list[dict[str, Any]] = []
    failures: list[dict[str, Any]] = []
    valuation_witness_samples: dict[str, dict[str, Any]] = {}
    fragility_accumulator = _new_fragility_accumulator()
    local_layer_accumulator = _new_local_layer_accumulator()
    residue_formula_accumulator = _new_residue_formula_accumulator()
    canonical_selector_accumulator = _new_canonical_witness_selector_accumulator()
    sample_case_ids = {
        "b2_F1-2-3-4-5",
        "b2_F6",
        "b3_F4-6-8-10-12",
        "b11_F8-9-10-11-12",
    }
    for base in SEARCH_BASES:
        for subset_size in range(1, MAX_SUBSET_SIZE + 1):
            for subset in itertools.combinations(range(1, MAX_N + 1), subset_size):
                row = _build_case(base, subset)
                compact_row = _compact_case(row)
                case_rows.append(compact_row)
                _maybe_add_valuation_samples(valuation_witness_samples, row)
                _accumulate_proof_fragility(fragility_accumulator, row)
                _accumulate_local_layer_certificates(
                    local_layer_accumulator,
                    row,
                    residue_formula_accumulator,
                )
                _accumulate_canonical_witness_selector(canonical_selector_accumulator, row)
                if row["case_id"] in sample_case_ids:
                    detailed_sample_cases.append(row)
                if row["pass_fail"] != "pass":
                    failures.append(row)
                    if row not in detailed_sample_cases:
                        detailed_sample_cases.append(row)
                elif len(detailed_sample_cases) < 4 and row["case_id"] not in sample_case_ids:
                    detailed_sample_cases.append(row)
    status_counts = dict(sorted(Counter(row["pass_fail"] for row in case_rows).items()))
    certified_count = sum(1 for row in case_rows if row["pass_fail"] == "pass")
    collapse_summary = {
        "criterion_id": "collapse_divisor_criterion",
        "status": "PASS"
        if not any(row["collapse_divisor_collapse_count"] or row["collapse_divisor_equivalence_mismatch_count"] for row in case_rows)
        else "FAIL",
        "prime_component_test_count": sum(row["collapse_divisor_prime_check_count"] for row in case_rows),
        "collapse_count": sum(row["collapse_divisor_collapse_count"] for row in case_rows),
        "equivalence_mismatch_count": sum(
            row["collapse_divisor_equivalence_mismatch_count"] for row in case_rows
        ),
        "case_with_collapse_count": sum(1 for row in case_rows if row["collapse_divisor_collapse_count"]),
        "case_with_equivalence_mismatch_count": sum(
            1 for row in case_rows if row["collapse_divisor_equivalence_mismatch_count"]
        ),
    }
    valuation_summary = _valuation_witness_summary(case_rows)
    proof_fragility_summary = _finalize_proof_fragility(fragility_accumulator)
    local_layer_certificate_summary = _finalize_local_layer_certificate_kernel(
        local_layer_accumulator,
        proof_fragility_summary,
    )
    residue_formula_summary = _finalize_residue_formula_kernel(residue_formula_accumulator)
    canonical_selector_summary = _finalize_canonical_witness_selector_kernel(canonical_selector_accumulator)
    minimal_counterexample = None
    if failures:
        minimal_counterexample = min(
            failures,
            key=lambda row: (max(row["F"]), len(row["F"]), row["b"], row["L"], row["case_id"]),
        )
    return {
        "search_id": "finite_period_noncollapse_bounded_certificate_grid_v0",
        "search_config": {
            "bases": SEARCH_BASES,
            "max_n": MAX_N,
            "max_subset_size": MAX_SUBSET_SIZE,
            "case_generation": "all nonempty subsets F of {1..max_n} with size <= max_subset_size for each base",
            "factorization_backend": "sympy.factorint",
            "order_test": "ord_Q(b) divides L because Q divides lcm_{n in F}(b^n - 1); reduce L by prime factors while b^(L/p)=1 mod Q",
            "artifact_compaction": "all cases are fully computed; all-case rows store Q/factorization digests, while detailed denominator/factorization certificates are retained for samples and every failure",
        },
        "summary": {
            "case_count": len(case_rows),
            "pass_count": status_counts.get("pass", 0),
            "fail_count": status_counts.get("fail", 0),
            "certified_case_count": certified_count,
            "status_counts": status_counts,
            "minimal_counterexample": minimal_counterexample,
            "collapse_divisor_criterion": collapse_summary,
            "valuation_witness_route": valuation_summary,
            "proof_fragility_suite": proof_fragility_summary,
            "local_layer_certificate_kernel": local_layer_certificate_summary,
            "residue_formula_kernel": residue_formula_summary,
            "canonical_witness_selector_kernel": canonical_selector_summary,
        },
        "case_rows": case_rows,
        "detailed_sample_cases": detailed_sample_cases,
        "failure_cases": failures,
        "valuation_witness_sample_rows": list(valuation_witness_samples.values()),
    }


def _project_finite_search_results(results: Mapping[str, Any]) -> dict[str, Any]:
    case_rows = list(results["case_rows"])
    detailed_sample_cases = list(results["detailed_sample_cases"])
    failure_cases = list(results["failure_cases"])
    valuation_witness_sample_rows = list(results["valuation_witness_sample_rows"])
    case_row_fields = sorted(case_rows[0].keys()) if case_rows else []
    return {
        "search_id": results["search_id"],
        "search_config": results["search_config"],
        "summary": results["summary"],
        "case_digest_manifest": {
            "row_schema": "period_noncollapse_compact_case_digest_v1",
            "row_count": len(case_rows),
            "case_rows_sha256": _sha256(case_rows),
            "case_row_fields": case_row_fields,
            "first_case_id": case_rows[0]["case_id"] if case_rows else None,
            "last_case_id": case_rows[-1]["case_id"] if case_rows else None,
            "sample_case_ids": [row["case_id"] for row in detailed_sample_cases],
            "failure_case_ids": [row["case_id"] for row in failure_cases],
            "full_case_policy": "The builder computes every case on each run; committed JSON stores a deterministic digest manifest plus detailed samples and every failure.",
        },
        "detailed_sample_cases": detailed_sample_cases,
        "failure_cases": failure_cases,
        "valuation_witness_sample_rows": valuation_witness_sample_rows,
    }


