def _exception_inventory(results: Mapping[str, Any]) -> dict[str, Any]:
    flag_counts: Counter[str] = Counter()
    examples: dict[str, list[str]] = {}
    for row in results["case_rows"]:
        for flag in row["exception_flags"]:
            flag_counts[flag] += 1
            examples.setdefault(flag, [])
            if len(examples[flag]) < 8:
                examples[flag].append(row["case_id"])
    return {
        "flag_counts": dict(sorted(flag_counts.items())),
        "examples": examples,
        "interpretation": "Exception flags are audit leads; none is a counterexample unless pass_fail is fail.",
    }


