def _provider_roles() -> list[dict[str, Any]]:
    return [
        {
            "role_id": "cyclotomic_algebraist",
            "allowed": True,
            "input_boundary": "finite rational-function statement and certificate samples only",
            "forbidden": "discussion of the infinite Erdos #257 proof",
        },
        {
            "role_id": "p_adic_number_theorist",
            "allowed": True,
            "input_boundary": "integer specialization, primitive-divisor, LTE, and cancellation questions for finite F only",
            "forbidden": "claiming the manuscript route is proved",
        },
        {
            "role_id": "counterexample_hunter",
            "allowed": True,
            "input_boundary": "search for finite b,F with ord_Q(b) < lcm(F) or missing certificate hypotheses",
            "forbidden": "unbounded all-Erdos crawling",
        },
        {
            "role_id": "lean_formalizer",
            "allowed": True,
            "input_boundary": "translate the finite certificate checker into Lean targets",
            "forbidden": "final Lean proof body for Erdos #257",
        },
        {
            "role_id": "proof_completion_worker_for_erdos257",
            "allowed": False,
            "input_boundary": "blocked",
            "forbidden": "solve or complete the infinite Erdos #257 proof",
        },
    ]


def _dag_node_updates(results: Mapping[str, Any]) -> list[dict[str, Any]]:
    summary = results["summary"]
    if summary["fail_count"]:
        proposed_period_status = "falsified_or_hypothesis_limited_pending_human_review"
    else:
        proposed_period_status = "conjectural_bridge_with_bounded_certificate_pattern"
    return [
        {
            "node_id": "period_noncollapse_conjecture_17_20",
            "current_status": "conjectural_bridge",
            "proposed_status": proposed_period_status,
            "evidence_ref": STRIKE_PATH.as_posix(),
            "change_boundary": "This strike projection proposes the update; the obligation DAG remains the authoritative graph until its builder consumes it.",
        },
        {
            "node_id": "finite_stress_period_noncollapse_scan",
            "current_status": "empirical_observation",
            "proposed_status": "superseded_by_certificate_search",
            "evidence_ref": finite_harness.HARNESS_PATH.as_posix(),
            "change_boundary": "Tiny scan remains valid but lower resolution than the strike grid.",
        },
        {
            "node_id": "finite_period_noncollapse_strike",
            "current_status": "absent_from_dag",
            "proposed_status": "empirical_observation_or_counterexample_lane",
            "evidence_ref": STRIKE_PATH.as_posix(),
            "change_boundary": "Add as DAG node only after reviewing whether this pass found a counterexample or just a certificate pattern.",
        },
    ]


def _next_decisive_experiment(results: Mapping[str, Any]) -> dict[str, Any]:
    summary = results["summary"]
    if summary["minimal_counterexample"]:
        return {
            "outcome": "counterexample_found",
            "next_step": "Shrink and independently verify the minimal counterexample; update the DAG and keep upstream action blocked.",
            "case_ref": summary["minimal_counterexample"]["case_id"],
        }
    valuation_route = summary["valuation_witness_route"]
    proof_fragility = summary["proof_fragility_suite"]
    local_layer = summary["local_layer_certificate_kernel"]
    residue_formula = summary["residue_formula_kernel"]
    canonical_selector = summary["canonical_witness_selector_kernel"]
    if local_layer["counterexample_or_bug_count"]:
        return {
            "outcome": "local_layer_certificate_found_bug_or_counterexample",
            "next_step": "Shrink and independently verify the local-layer counterexample/bug row before any provider council.",
            "case_ref": local_layer["counterexample_or_bug_certificates"][0]["case_id"]
            if local_layer["counterexample_or_bug_certificates"]
            else None,
        }
    if local_layer["residue_zero_unresolved_count"]:
        return {
            "outcome": "local_layer_certificate_residue_zero_rows_block_proof_kernel",
            "next_step": "Inspect residue-zero rows and decide whether witness reselection or theorem hypotheses need repair.",
            "case_ref": local_layer["unresolved_certificates"][0]["case_id"]
            if local_layer["unresolved_certificates"]
            else None,
        }
    if residue_formula["formula_mismatch_count"]:
        return {
            "outcome": "residue_formula_lift_found_formula_mismatch",
            "next_step": "Inspect residue-formula mismatch rows before any Lean or provider work.",
            "case_ref": residue_formula["mismatch_samples"][0]["case_id"]
            if residue_formula["mismatch_samples"]
            else None,
        }
    if residue_formula["formula_residue_zero_count"]:
        return {
            "outcome": "residue_formula_lift_found_zero_shape",
            "next_step": "Inspect residue-zero formula shapes and decide whether the theorem hypotheses or certificate compiler need repair.",
            "case_ref": residue_formula["zero_samples"][0]["case_id"] if residue_formula["zero_samples"] else None,
        }
    if residue_formula["formula_unavailable_count"]:
        return {
            "outcome": "residue_formula_lift_has_unavailable_exception_shape",
            "next_step": "Add an explicit residue-formula branch for the unavailable exception shape.",
            "case_ref": residue_formula["unavailable_samples"][0]["case_id"]
            if residue_formula["unavailable_samples"]
            else None,
        }
    if canonical_selector["route_status"] != "PASS":
        return {
            "outcome": "canonical_witness_selector_partial_residue_formula_fallback_needed",
            "next_step": "Inspect canonical selector disconfirming rows and keep residue_formula_kernel active for unresolved rows.",
            "case_ref": canonical_selector["disconfirming_rows"][0]["case_id"]
            if canonical_selector["disconfirming_rows"]
            else None,
        }
    if proof_fragility["failure_count"] and canonical_selector["route_status"] == "PASS":
        return {
            "outcome": "candidate_paper_proof_closure_emitted_pending_referee_and_lean",
            "next_step": "Lean-check the order-drop-to-ModEq supplier, then compose the one-direction collapse-divisor theorem before selector/existence work.",
            "case_ref": None,
        }
    if proof_fragility["failure_count"] and local_layer["route_status"] == "PASS":
        return {
            "outcome": "residue_formula_lifted_certificates_pending_lean",
            "next_step": "Lean-check the odd-prime residue formula and the small residue-shape obligations before any provider/referee run on witness existence.",
            "case_ref": None,
        }
    if proof_fragility["failure_count"]:
        return {
            "outcome": "proof_fragility_suite_found_gap",
            "next_step": "Shrink the failing proof-route assumption before any referee packet or Lean claim.",
            "case_ref": proof_fragility["failure_samples"][0]["case_id"] if proof_fragility["failure_samples"] else None,
        }
    if valuation_route["counterexample_or_bug_count"] == 0 and valuation_route["unexplained_noncollapse_count"] == 0:
        return {
            "outcome": "proof_kernel_split_emitted_certificate_kernel_pending_lean_and_existence_referee",
            "next_step": "Lean-check the certificate kernel independently of Zsigmondy, then referee the witness-existence kernel.",
            "case_ref": None,
        }
    if valuation_route["counterexample_or_bug_count"]:
        return {
            "outcome": "valuation_witness_route_found_bug_or_counterexample",
            "next_step": "Shrink and independently verify the named valuation/collapse mismatch before any provider council.",
            "case_ref": None,
        }
    return {
        "outcome": "valuation_witness_route_has_named_gaps",
        "next_step": "Mine the unexplained non-collapse rows into sharper hypotheses before provider council.",
        "case_ref": None,
    }


