def main(argv: Sequence[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--check", action="store_true", help="Validate generated artifacts without writing.")
    parser.add_argument("--json", action="store_true", help="Accepted for proof-tail command symmetry; output is JSON.")
    parser.add_argument(
        "--frontier-conveyor-plan",
        action="store_true",
        help="Plan the next bounded direct-prime frontier action without writing.",
    )
    parser.add_argument(
        "--frontier-conveyor-apply",
        action="store_true",
        help="Apply bounded frontier action inputs to this strike generator.",
    )
    parser.add_argument(
        "--frontier-conveyor-check",
        action="store_true",
        help="Validate the latest persistent frontier conveyor receipt.",
    )
    parser.add_argument(
        "--frontier-conveyor-layout-write",
        action="store_true",
        help="Write the conveyor-step layout verification receipt.",
    )
    parser.add_argument(
        "--frontier-conveyor-layout-check",
        action="store_true",
        help="Validate the persisted conveyor-step layout receipt against current receipts.",
    )
    parser.add_argument(
        "--frontier-split-wave-policy-write",
        action="store_true",
        help="Write the split-wave admission policy receipt for a blocked frontier candidate.",
    )
    parser.add_argument(
        "--frontier-split-wave-policy-check",
        action="store_true",
        help="Validate the persisted split-wave admission policy receipt.",
    )
    parser.add_argument(
        "--max-steps",
        type=int,
        default=1,
        help="Maximum frontier conveyor actions to apply in one tranche.",
    )
    parser.add_argument(
        "--max-direct-specs",
        type=int,
        default=1,
        help="Maximum direct semantic specs to bind in one conveyor tranche.",
    )
    parser.add_argument(
        "--max-lift-helpers",
        type=int,
        default=2,
        help="Maximum row-invisible lift helpers to bind in one conveyor tranche.",
    )
    args = parser.parse_args(argv)
    if args.frontier_conveyor_plan:
        result = _direct_prime_frontier_conveyor_plan()
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] == "PASS" else 1
    if args.frontier_conveyor_apply:
        result = _direct_prime_frontier_conveyor_apply(
            max_steps=args.max_steps,
            max_direct_specs=args.max_direct_specs,
            max_lift_helpers=args.max_lift_helpers,
        )
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] in {"PASS", "NOOP"} else 1
    if args.frontier_conveyor_check:
        result = _direct_prime_frontier_conveyor_check()
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] == "PASS" else 1
    if args.frontier_conveyor_layout_write:
        result = _write_direct_prime_frontier_conveyor_layout_receipt()
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] == "PASS" else 1
    if args.frontier_conveyor_layout_check:
        result = _direct_prime_frontier_conveyor_layout_check()
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] == "PASS" else 1
    if args.frontier_split_wave_policy_write:
        result = _write_direct_prime_frontier_split_wave_policy_receipt()
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] == "PASS" else 1
    if args.frontier_split_wave_policy_check:
        result = _direct_prime_frontier_split_wave_policy_check()
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] == "PASS" else 1
    if args.check:
        result = check_outputs()
        print(json.dumps(result, ensure_ascii=True, indent=2, sort_keys=True))
        return 0 if result["status"] == "PASS" else 1
    receipt = write_outputs()
    print(json.dumps(receipt, ensure_ascii=True, indent=2, sort_keys=True))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
